import requests
import re
import logging
import hashlib
from urllib.parse import urlparse

# Set up logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Define allowed URL patterns (only allow New Relic webhook domains)
allowed_urls = re.compile(r'^https://api\.newrelic\.com/|^https://webhook\.newrelic\.com/')

def filter_alerts(alerts):
    """Filter alerts based on severity and relevance"""
    if not alerts or not isinstance(alerts, list):
        return []

    # Filter for critical and warning alerts only
    return [alert for alert in alerts if 
            isinstance(alert, dict) and
            alert.get('severity') in ['critical', 'warning']]

def dedupe_alerts(alerts):
    """Remove duplicate alerts based on alert ID"""
    if not alerts:
        return []

    unique_alerts = {}
    for alert in alerts:
        if isinstance(alert, dict) and 'id' in alert:
            unique_alerts[alert['id']] = alert

    return list(unique_alerts.values())

def process_alerts(alerts):
    """Process the filtered and deduped alerts"""
    if not alerts:
        logging.info("No alerts to process")
        return

    logging.info(f"Processing {len(alerts)} alerts")
    for alert in alerts:
        if isinstance(alert, dict):
            alert_id = alert.get('id', 'unknown')
            severity = alert.get('severity', 'unknown')
            message = alert.get('message', 'No message')
            logging.info(f"Alert {alert_id}: {severity} - {message}")

            # Additional processing would go here
            # e.g., update database, trigger notifications, etc.

def fetch_alerts(url):
    """Fetch alerts from the webhook URL with proper validation and error handling"""
    try:
        # Validate URL format
        if not url or not isinstance(url, str):
            logging.error("Invalid URL format")
            return

        # Check against allowed URL patterns
        if not allowed_urls.match(url):
            logging.error("URL not from an authorized New Relic domain")
            return

        # Verify URL has proper scheme
        parsed_url = urlparse(url)
        if parsed_url.scheme not in ['http', 'https']:
            logging.error("URL must use HTTP or HTTPS protocol")
            return

        # Add timeout to prevent hanging connections
        resp = requests.get(url, timeout=10)

        # Check response status
        resp.raise_for_status()

        # Parse JSON response
        try:
            data = resp.json()
        except ValueError:
            logging.error("Invalid JSON response from webhook")
            return

        # Validate expected data structure
        if not isinstance(data, dict) or 'alerts' not in data:
            logging.error("Unexpected response format from webhook")
            return

        alerts = filter_alerts(data["alerts"])
        alerts = dedupe_alerts(alerts)
        process_alerts(alerts)

    except requests.exceptions.RequestException as e:
        logging.error(f"Request error: {e}")
    except Exception as e:
        logging.error(f"Unexpected error: {e}")

# Main execution with input validation
def main():
    try:
        webhook_url = input("Enter webhook URL: ").strip()
        fetch_alerts(webhook_url)
    except KeyboardInterrupt:
        logging.info("Operation cancelled by user")
    except Exception as e:
        logging.error(f"Error in main execution: {e}")

if __name__ == "__main__":
    main()

