@login_required
def upload_file():
    # Check if the post request has the file part
    if 'file' not in request.files:
        return redirect(request.url)

    files = request.files.getlist('file')
    if not files or files[0].filename == '':
        return render_template('index.html', error='No files selected')

    # Create a user-specific directory for uploads and index
    user_id = session['user_id']
    user_upload_folder = os.path.join(app.config['UPLOAD_FOLDER'], user_id)
    user_index_folder = os.path.join(app.config['INDEX_FOLDER'], user_id)

    os.makedirs(user_upload_folder, exist_ok=True)
    os.makedirs(user_index_folder, exist_ok=True)

    # Define schema for search index
    schema = Schema(path=ID(stored=True), content=TEXT)

    # Create or open index
    if not os.listdir(user_index_folder):
        ix = create_in(user_index_folder, schema)
    else:
        ix = open_dir(user_index_folder)

    # Process each file
    successful_files = []
    for file in files:
        if file and allowed_file(file.filename):
            # Secure the filename and save the file
            filename = secure_filename(file.filename)
            file_path = os.path.join(user_upload_folder, filename)

            # Check if file already exists and generate unique name if needed
            base, ext = os.path.splitext(filename)
            counter = 1
            while os.path.exists(file_path):
                filename = f"{base}_{counter}{ext}"
                file_path = os.path.join(user_upload_folder, filename)
                counter += 1

            try:
                file.save(file_path)

                # Index the file content
                writer = ix.writer()
                with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
                    content = f.read()
                writer.add_document(path=file_path, content=content)
                writer.commit()

                successful_files.append(filename)
                logger.info(f"File {filename} uploaded and indexed successfully")
            except Exception as e:
                logger.error(f"Error processing file {filename}: {str(e)}")
                return render_template('index.html', error=f"Error processing file: {str(e)}")

    return render_template('index.html', successful_files=successful_files)

@app.route('/search', methods=['GET'])
@login_required
def search():
    query_text = request.args.get('query', '')
    if not query_text:
        return render_template('search.html', results=[])

    user_id = session['user_id']
    user_index_folder = os.path.join(app.config['INDEX_FOLDER'], user_id)

    if not os.path.exists(user_index_folder) or not os.listdir(user_index_folder):
        return render_template('search.html', error="No index found. Please upload documents first.")

    try:
        ix = open_dir(user_index_folder)
        with ix.searcher() as searcher:
            query_parser = QueryParser("content", ix.schema)
            query = query_parser.parse(query_text)
            results = searcher.search(query, limit=20)

            search_results = []
            for result in results:
                file_path = result['path']
                filename = os.path.basename(file_path)
                search_results.append({
                    'filename': filename,
                    'path': file_path
                })

            return render_template('search.html', results=search_results, query=query_text)
    except Exception as e:
        logger.error(f"Search error: {str(e)}")
        return render_template('search.html', error=f"Search error: {str(e)}")

