    # Validate the filename is within the user's directory
    requested_path = os.path.abspath(os.path.join(user_upload_folder, os.path.basename(filename)))
    if not requested_path.startswith(os.path.abspath(user_upload_folder)):
        return "Access denied", 403

    return send_from_directory(user_upload_folder, os.path.basename(filename))

@app.route('/delete/<path:filename>')
@login_required
def delete_file(filename):
    user_id = session['user_id']
    user_upload_folder = os.path.join(app.config['UPLOAD_FOLDER'], user_id)
    user_index_folder = os.path.join(app.config['INDEX_FOLDER'], user_id)

    # Validate the filename is within the user's directory
    requested_path = os.path.abspath(os.path.join(user_upload_folder, os.path.basename(filename)))
    if not requested_path.startswith(os.path.abspath(user_upload_folder)):
        return "Access denied", 403

    try:
        # Delete the file
        os.remove(requested_path)

        # Re-index after deletion
        if os.path.exists(user_index_folder):
            shutil.rmtree(user_index_folder)
            os.makedirs(user_index_folder, exist_ok=True)

            # Reindex remaining files
            schema = Schema(path=ID(stored=True), content=TEXT)
            ix = create_in(user_index_folder, schema)
            writer = ix.writer()

            for file in os.listdir(user_upload_folder):
                file_path = os.path.join(user_upload_folder, file)
                if os.path.isfile(file_path):
                    with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
                        content = f.read()
                    writer.add_document(path=file_path, content=content)
            writer.commit()

        return redirect(url_for('index'))
    except Exception as e:
        logger.error(f"Error deleting file {filename}: {str(e)}")
        return render_template('index.html', error=f"Error deleting file: {str(e)}")

