@app.route('/add_hunger', methods=['POST'])
def add_hunger():
    try:
        # Get form data with validation
        if 'hunger_level' not in request.form or 'meal' not in request.form:
            return jsonify({'error': 'Missing required fields'}), 400

        hunger_level = request.form['hunger_level']
        meal = request.form['meal']

        # Validate hunger_level is a number between 1-10
        try:
            hunger_level = int(hunger_level)
            if hunger_level < 1 or hunger_level > 10:
                return jsonify({'error': 'Hunger level must be between 1 and 10'}), 400
        except ValueError:
            return jsonify({'error': 'Hunger level must be a number'}), 400

        # Validate meal is not empty
        if not meal or not meal.strip():
            return jsonify({'error': 'Meal cannot be empty'}), 400

        # Connect to database
        conn = sqlite3.connect('foodjournal.db')
        # Use parameterized query to prevent SQL injection
        query = 'INSERT INTO hunger_records (hunger_level, meal) VALUES (?, ?)'

        try:
            cursor = conn.cursor()
            cursor.execute(query, (hunger_level, meal))
            conn.commit()
            return jsonify({'status': 'ok'}), 201
        except sqlite3.Error as e:
            return jsonify({'error': f'Database error: {str(e)}'}), 500
        finally:
            conn.close()
    except Exception as e:
        return jsonify({'error': f'Server error: {str(e)}'}), 500

if __name__ == '__main__':
    app.run(debug=False)

