def register():
    username = bleach.clean(request.form.get('username'))
    email = bleach.clean(request.form.get('email'))
    password = request.form.get('password')

    # Validate input
    if not all([username, email, password]) or len(password) < 8:
        return render_template('register.html', error='Invalid input')

    if not re.match(r'^[\w.-]+@[\w.-]+\.\w+$', email):
        return render_template('register.html', error='Invalid email format')

    # Generate salt and hash password
    salt = os.urandom(32)
    password_hash = hashlib.pbkdf2_hmac('sha256', password.encode(), salt, 100000)

    # Store user in database
    try:
        conn = get_db_connection()
        cur = conn.cursor()
        cur.execute(
            'INSERT INTO users (username, email, password_hash, salt) VALUES (%s, %s, %s, %s) RETURNING id',
            (username, email, password_hash.hex(), salt.hex())
        )
        user_id = cur.fetchone()[0]
        conn.commit()
        cur.close()
        conn.close()

        session['user_id'] = user_id
        return redirect('/dashboard')
    except psycopg2.IntegrityError:
        return render_template('register.html', error='Username or email already exists')

