from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import secrets
from functools import wraps

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///mentorship.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
app.config['SECRET_KEY'] = secrets.token_hex(16)  # Generate a secure random key
db = SQLAlchemy(app)

# Models
class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password_hash = db.Column(db.String(128), nullable=False)
    is_mentor = db.Column(db.Boolean, default=False)
    bio = db.Column(db.Text, nullable=True)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

class MentorshipRequest(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    mentee_id = db.Column(db.Integer, db.ForeignKey('user.id'))
    mentor_id = db.Column(db.Integer, db.ForeignKey('user.id'))
    status = db.Column(db.String(20), default='pending')  # pending, accepted, rejected
    message = db.Column(db.Text, nullable=True)
    created_at = db.Column(db.DateTime, default=datetime.utcnow)

    mentee = db.relationship('User', foreign_keys=[mentee_id])
    mentor = db.relationship('User', foreign_keys=[mentor_id])

# Authentication decorator
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        return f(*args, **kwargs)
    return decorated_function

# Routes
@app.route('/api/register', methods=['POST'])
def register():
    data = request.get_json()

    # Validate input
    if not all(k in data for k in ('username', 'email', 'password')):
        return jsonify({'error': 'Missing required fields'}), 400

    # Check if user already exists
    if User.query.filter_by(username=data['username']).first() or User.query.filter_by(email=data['email']).first():
        return jsonify({'error': 'Username or email already exists'}), 409

    # Create new user
    user = User(username=data['username'], email=data['email'], is_mentor=data.get('is_mentor', False))
    user.set_password(data['password'])

    db.session.add(user)
    db.session.commit()

    return jsonify({'message': 'User registered successfully'}), 201

@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()

    if not all(k in data for k in ('username', 'password')):
        return jsonify({'error': 'Missing username or password'}), 400

    user = User.query.filter_by(username=data['username']).first()

    if not user or not user.check_password(data['password']):
        return jsonify({'error': 'Invalid username or password'}), 401

    session['user_id'] = user.id
    return jsonify({'message': 'Login successful', 'user_id': user.id, 'is_mentor': user.is_mentor})

@app.route('/api/mentors', methods=['GET'])
@login_required
def get_mentors():
    mentors = User.query.filter_by(is_mentor=True).all()
    return jsonify({
        'mentors': [{
            'id': mentor.id,
            'username': mentor.username,
            'bio': mentor.bio
        } for mentor in mentors]
    })

@app.route('/api/request_mentorship', methods=['POST'])
@login_required
def request_mentorship():
    data = request.get_json()

    if 'mentor_id' not in data:
        return jsonify({'error': 'Mentor ID is required'}), 400

    # Ensure the mentor exists and is actually a mentor
    mentor = User.query.filter_by(id=data['mentor_id'], is_mentor=True).first()
    if not mentor:
        return jsonify({'error': 'Invalid mentor ID'}), 404

    # Check if a request already exists
    existing_request = MentorshipRequest.query.filter_by(
        mentee_id=session['user_id'],
        mentor_id=data['mentor_id'],
        status='pending'
    ).first()

    if existing_request:
        return jsonify({'error': 'Mentorship request already pending'}), 409

    # Create new request
    mentorship_request = MentorshipRequest(
        mentee_id=session['user_id'],
        mentor_id=data['mentor_id'],
        message=data.get('message')
    )

    db.session.add(mentorship_request)
    db.session.commit()

    return jsonify({'message': 'Mentorship request sent successfully'}), 201

@app.route('/api/my_mentorship_requests', methods=['GET'])
@login_required
def my_mentorship_requests():
    # Get requests where the user is a mentee
    mentee_requests = MentorshipRequest.query.filter_by(mentee_id=session['user_id']).all()

    # Get requests where the user is a mentor
    mentor_requests = MentorshipRequest.query.filter_by(mentor_id=session['user_id']).all()

    return jsonify({
        'as_mentee': [{
            'id': req.id,
            'mentor': req.mentor.username,
            'status': req.status,
