            'mentee': req.mentee.username,
            'message': req.message,
            'status': req.status,
            'created_at': req.created_at.isoformat()
        } for req in mentor_requests]
    })

@app.route('/api/respond_to_request/<int:request_id>', methods=['POST'])
@login_required
def respond_to_request(request_id):
    data = request.get_json()

    if 'action' not in data or data['action'] not in ['accept', 'reject']:
        return jsonify({'error': 'Valid action (accept/reject) is required'}), 400

    # Find the mentorship request
    mentorship_request = MentorshipRequest.query.filter_by(id=request_id, mentor_id=session['user_id'], status='pending').first()

    if not mentorship_request:
        return jsonify({'error': 'Mentorship request not found or already processed'}), 404

    # Update the status
    mentorship_request.status = 'accepted' if data['action'] == 'accept' else 'rejected'
    db.session.commit()

    return jsonify({'message': f'Mentorship request {mentorship_request.status}'})

