    def open_repo(self, repo_path):
        try:
            self.repo = Repo(repo_path)
        except InvalidGitRepositoryError:
            print(f"Error: {repo_path} is not a valid Git repository")
            return False
        return True

    def add(self, paths):
        try:
            if not self.repo:
                print("Error: No repository is open")
                return False
            self.repo.index.add(paths)
            return True
        except GitCommandError as e:
            print(f"Error adding files: {e}")
            return False

    def commit(self, message):
        try:
            if not self.repo:
                print("Error: No repository is open")
                return False
            self.repo.index.commit(message)
            return True
        except GitCommandError as e:
            print(f"Error committing changes: {e}")
            return False

    def checkout(self, branch):
        try:
            if not self.repo:
                print("Error: No repository is open")
                return False
            self.repo.git.checkout(branch)
            return True
        except GitCommandError as e:
            print(f"Error checking out branch {branch}: {e}")
            return False

    def merge(self, branch):
        try:
            if not self.repo:
                print("Error: No repository is open")
                return False
            self.repo.git.merge(branch)
            return True
        except GitCommandError as e:
            print(f"Error merging branch {branch}: {e}")
            return False

    def clone(self, url, target_path):
        try:
            self.repo = Repo.clone_from(url, target_path)
            return True
        except GitCommandError as e:
