            origin = self.repo.remote(remote_name)
            if branch:
                origin.push(branch)
            else:
                origin.push()
            return True
        except GitCommandError as e:
            print(f"Error pushing to remote: {e}")
            return False

    def pull(self, remote_name='origin'):
        try:
            if not self.repo:
