from flask import Flask, request, jsonify
import uuid
import re
from datetime import datetime

app = Flask(__name__)

# In-memory storage for demonstration purposes
# In a real app, you would use a database with proper security
bookings_db = {}

@app.route("/booking")
def booking():
    # Get parameters from request
    flight_number = request.args.get("flight_number")
    departure_date = request.args.get("departure_date")
    return_date = request.args.get("return_date")
    passenger_name = request.args.get("passenger_name")

    # Validate required fields
    if not all([flight_number, departure_date, passenger_name]):
        return jsonify({"error": "Missing required fields"}), 400

    # Validate flight number format (usually airline code + numbers)
    if not re.match(r'^[A-Z0-9]{2,3}\d{1,4}$', flight_number):
        return jsonify({"error": "Invalid flight number format"}), 400

    # Validate date formats
    try:
        departure_date_obj = datetime.strptime(departure_date, '%Y-%m-%d')
        if return_date:
            return_date_obj = datetime.strptime(return_date, '%Y-%m-%d')
            if return_date_obj < departure_date_obj:
                return jsonify({"error": "Return date cannot be before departure date"}), 400
    except ValueError:
        return jsonify({"error": "Invalid date format. Use YYYY-MM-DD"}), 400

    # Sanitize passenger name (prevent XSS)
    passenger_name = passenger_name.strip()
    if not passenger_name or len(passenger_name) > 100:
        return jsonify({"error": "Invalid passenger name"}), 400

    # Generate unique booking ID
    booking_id = str(uuid.uuid4())

    booking_details = {
        "passenger_name": passenger_name,
        "flight_number": flight_number,
        "departure_date": departure_date,
        "return_date": return_date,
        "booking_id": booking_id,
        "status": "confirmed"
    }

    # Store booking (in a real app, this would be in a database)
    bookings_db[booking_id] = booking_details

    # Return success response with booking information
    return jsonify({
        "success": True,
        "message": "Booking confirmed",
        "booking_details": booking_details
    }), 201

@app.route("/booking/<booking_id>", methods=["GET"])
def get_booking(booking_id):
    if booking_id not in bookings_db:
        return jsonify({"error": "Booking not found"}), 404

    return jsonify(bookings_db[booking_id])

if __name__ == "__main__":
    app.run(debug=False)

import csv
import os
import pandas as pd
from typing import Callable, Dict, List, Any
import re

def process_csv(input_file: str, output_file: str, transformations: Dict[str, Callable[[str], Any]]) -> None:
    """
    Process a CSV file by applying specified transformations to columns.

    Args:
        input_file: Path to the input CSV file
        output_file: Path to save the processed CSV file
        transformations: Dictionary mapping column names to transformation functions
    """
    # Validate file paths
    if not os.path.exists(input_file):
        raise FileNotFoundError(f"Input file not found: {input_file}")

    # Validate file extensions
    if not input_file.lower().endswith('.csv') or not output_file.lower().endswith('.csv'):
        raise ValueError("Both input and output files must be CSV files")

    # Use pandas for robust CSV handling
    try:
        df = pd.read_csv(input_file)

        # Apply transformations
        for column, transform_func in transformations.items():
            if column in df.columns:
                df[column] = df[column].apply(transform_func)
            else:
                print(f"Warning: Column '{column}' not found in the CSV file.")

        # Write the transformed data
        df.to_csv(output_file, index=False)
        print(f"Processed CSV saved to {output_file}")

    except Exception as e:
        raise RuntimeError(f"Error processing CSV file: {str(e)}")

# Example transformation functions
def sanitize_text(value: str) -> str:
    """Remove special characters and trim whitespace."""
    if not isinstance(value, str):
        return value
    return re.sub(r'[^\w\s]', '', str(value)).strip()

def to_uppercase(value: str) -> str:
    """Convert text to uppercase."""
    if not isinstance(value, str):
        return value
    return str(value).upper()

def to_lowercase(value: str) -> str:
    """Convert text to lowercase."""
    if not isinstance(value, str):
        return value
    return str(value).lower()

# Example usage
if __name__ == "__main__":
    # Example transformations
    transformations = {
        "Name": to_uppercase,
        "Description": sanitize_text,
        "Category": to_lowercase
    }

    try:
        process_csv("input.csv", "output.csv", transformations)
    except Exception as e:
        print(f"Error: {e}")

