from flask import Flask, render_template, request, redirect, url_for, session, flash
from flask_wtf import FlaskForm
from flask_wtf.csrf import CSRFProtect
from wtforms import StringField, TextAreaField, FieldList, FormField, validators
import bleach
import sqlite3
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)
app.config['SECRET_KEY'] = os.urandom(32)  # Generate a random secret key
csrf = CSRFProtect(app)

class IngredientForm(FlaskForm):
    name = StringField('Ingredient', [validators.DataRequired(), validators.Length(min=1, max=100)])
    quantity = StringField('Quantity', [validators.DataRequired(), validators.Length(min=1, max=50)])

class RecipeForm(FlaskForm):
    title = StringField('Recipe Title', [validators.DataRequired(), validators.Length(min=3, max=100)])
    ingredients = FieldList(FormField(IngredientForm), min_entries=1)
    instructions = TextAreaField('Instructions', [validators.DataRequired(), validators.Length(min=10, max=5000)])

def get_db_connection():
    conn = sqlite3.connect('recipes.db')
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    conn = get_db_connection()
    conn.execute('''
    CREATE TABLE IF NOT EXISTS recipes (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT NOT NULL,
        instructions TEXT NOT NULL
    )''')

    conn.execute('''
    CREATE TABLE IF NOT EXISTS ingredients (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        recipe_id INTEGER NOT NULL,
        name TEXT NOT NULL,
        quantity TEXT NOT NULL,
        FOREIGN KEY (recipe_id) REFERENCES recipes (id)
    )''')
    conn.commit()
    conn.close()

@app.before_first_request
def setup():
    init_db()

@app.route('/')
def index():
    return render_template('recipe_form.html', form=RecipeForm())

@app.route('/submit', methods=['POST'])
def submit_recipe():
    form = RecipeForm()

    if form.validate_on_submit():
        # Sanitize user input to prevent XSS
        title = bleach.clean(form.title.data)
        instructions = bleach.clean(form.instructions.data)

        # Store in database using parameterized queries to prevent SQL injection
        conn = get_db_connection()
        cursor = conn.cursor()

        cursor.execute('INSERT INTO recipes (title, instructions) VALUES (?, ?)',
                      (title, instructions))
        recipe_id = cursor.lastrowid

        # Store ingredients
        for ingredient in form.ingredients.data:
            name = bleach.clean(ingredient['name'])
            quantity = bleach.clean(ingredient['quantity'])
            cursor.execute('INSERT INTO ingredients (recipe_id, name, quantity) VALUES (?, ?, ?)',
                          (recipe_id, name, quantity))

        conn.commit()
        conn.close()

        flash('Recipe submitted successfully!')
        return redirect(url_for('index'))

    return render_template('recipe_form.html', form=form)

