def write_to_file(data, filename):
    """Securely writes data to a file."""
    # Validate filename to prevent path traversal
    base_filename = os.path.basename(filename)
    if base_filename != filename:
        raise ValueError("Invalid filename: must not contain path separators")

    # Use a designated output directory
    output_dir = os.path.join(os.getcwd(), 'output')
    os.makedirs(output_dir, exist_ok=True)
    safe_path = os.path.join(output_dir, base_filename)

    try:
        with open(safe_path, 'w') as f:
            # Format structured data properly
            if isinstance(data, (list, tuple)):
                for row in data:
                    f.write(','.join(str(item) for item in row) + '\n')
            else:
                f.write(str(data))
        return True
    except IOError as e:
        print(f"Error writing to file: {e}")
        return False

import tarfile
import os
import logging

def extract_tar(tar_file, extract_to=None):
    """Extract files from a tar archive, handling corrupted files when possible.

    Args:
        tar_file: Path to the tar file
        extract_to: Directory to extract to (defaults to current directory)
    """
    if extract_to is None:
        extract_to = os.getcwd()

    # Ensure the target directory exists
    os.makedirs(extract_to, exist_ok=True)

    # Create a logger to track extraction issues
    logging.basicConfig(level=logging.INFO)
    logger = logging.getLogger('tar_extractor')

    try:
        # Open the tar file in read mode
        with tarfile.open(tar_file, 'r') as tar:
            # Check for any potentially unsafe files
            for member in tar.getmembers():
                # Prevent directory traversal attacks
                if member.name.startswith('/') or '..' in member.name:
                    logger.warning(f"Potentially unsafe path in archive: {member.name} - skipping")
                    continue

                # Extract files one by one, handling errors
                try:
                    # Extract to safe location
                    tar.extract(member, path=extract_to, set_attrs=False)
                    logger.info(f"Successfully extracted {member.name}")
                except (tarfile.ExtractError, OSError) as e:
                    logger.error(f"Failed to extract {member.name}: {e}")
    except tarfile.ReadError as e:
        logger.error(f"Error reading tar file {tar_file}: {e}")
        # Try to recover what we can by using the 'errorlevel' parameter
        try:
            with tarfile.open(tar_file, 'r', errorlevel=1) as tar:
                # Extract files with less strict error checking
                for member in tar.getmembers():
                    if member.name.startswith('/') or '..' in member.name:
                        continue
                    try:
                        tar.extract(member, path=extract_to, set_attrs=False)
                        logger.info(f"Recovered {member.name} from corrupted archive")
                    except Exception as e:
                        logger.error(f"Could not recover {member.name}: {e}")
        except Exception as e:
            logger.error(f"Archive too corrupted to process: {e}")

def extract_all_tars(path, extract_to=None):
    """Extract all tar files in a directory.

    Args:
        path: Directory containing tar files
        extract_to: Directory to extract to (defaults to subdirectories in path)
    """
    if not os.path.exists(path):
        raise ValueError(f"Directory not found: {path}")

    for tar_file in os.listdir(path):
        if tar_file.endswith(".tar"):
            tar_path = os.path.join(path, tar_file)
            # Extract to a subdirectory named after the tar file by default
            if extract_to is None:
                target_dir = os.path.join(path, os.path.splitext(tar_file)[0])
            else:
                target_dir = extract_to

            extract_tar(tar_path, target_dir)

