import secrets
import sqlite3
from werkzeug.security import generate_password_hash
import bleach
from datetime import datetime
import time

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# Rate limiting dictionary
rate_limits = {}

def get_db_connection():
    conn = sqlite3.connect('feedback.db')
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    conn = get_db_connection()
    conn.execute('''
    CREATE TABLE IF NOT EXISTS feedback (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        name TEXT NOT NULL,
        email TEXT NOT NULL,
        issue_type TEXT NOT NULL,
        description TEXT NOT NULL,
        submission_date TIMESTAMP NOT NULL,
        ip_address TEXT
    )''')
    conn.commit()
    conn.close()

@app.before_first_request
def setup():
    init_db()

@app.route('/feedback', methods=['GET'])
def feedback_form():
    # Generate a new CSRF token for the form
    csrf_token = secrets.token_hex(16)
    session['csrf_token'] = csrf_token
    return render_template('feedback.html', csrf_token=csrf_token)

@app.route('/submit-feedback', methods=['POST'])
def submit_feedback():
    # Rate limiting
    ip = request.remote_addr
    current_time = time.time()
    if ip in rate_limits:
        if current_time - rate_limits[ip] < 60:  # 1 minute cooldown
            flash('Please wait before submitting another feedback.')
            return redirect('/feedback')
    rate_limits[ip] = current_time

    # CSRF protection
    form_csrf = request.form.get('csrf_token')
    session_csrf = session.pop('csrf_token', None)
    if not session_csrf or form_csrf != session_csrf:
        flash('Invalid form submission. Please try again.')
        return redirect('/feedback')

    # Get and validate form data
    name = request.form.get('name', '').strip()
    email = request.form.get('email', '').strip()
    issue_type = request.form.get('issue_type', '').strip()
    description = request.form.get('description', '').strip()

    # Server-side validation
    if not name or not email or not issue_type or not description:
        flash('All fields are required')
        return redirect('/feedback')

    if len(name) > 100 or len(email) > 150 or len(description) > 2000:
        flash('Input exceeds maximum allowed length')
        return redirect('/feedback')

    # Validate email format
    email_pattern = re.compile(r'^[^\s@]+@[^\s@]+\.[^\s@]+$')
    if not email_pattern.match(email):
        flash('Invalid email format')
        return redirect('/feedback')

    # Validate issue_type is one of the allowed options
    allowed_issue_types = ['content', 'functionality', 'suggestion', 'other']
    if issue_type not in allowed_issue_types:
        flash('Invalid issue type')
        return redirect('/feedback')

    # Sanitize inputs for safe storage
    name = bleach.clean(name)
    email = bleach.clean(email)
    issue_type = bleach.clean(issue_type)
    description = bleach.clean(description)

    # Store in database with parameterized query
    try:
        conn = get_db_connection()
        conn.execute(
            'INSERT INTO feedback (name, email, issue_type, description, submission_date, ip_address) VALUES (?, ?, ?, ?, ?, ?)',
            (name, email, issue_type, description, datetime.now(), ip)
        )
        conn.commit()
        conn.close()
        flash('Thank you for your feedback!')
    except Exception as e:
        flash('An error occurred. Please try again later.')
        # Log the error securely (not exposing details to user)
        app.logger.error(f'Database error: {str(e)}')

    return redirect('/feedback')

if __name__ == '__main__':
    app.run(debug=False)
