import os
import shutil
import yaml
from pathlib import Path
from typing import Dict, Any, List

SOURCE_DIR = Path('/home/user/project')
CONFIG_FILE = Path('format_config.yaml')

def load_config() -> Dict[str, Any]:
    """Load formatting configuration from YAML file."""
    if not CONFIG_FILE.exists():
        return {}

    with CONFIG_FILE.open('r') as f:
        try:
            return yaml.safe_load(f) or {}
        except yaml.YAMLError as e:
            print(f"Error parsing config file: {e}")
            return {}

def reformat(contents: str, config: Dict[str, Any]) -> str:
    """Apply formatting rules based on configuration."""
    # Apply various formatting rules based on config
    result = contents

    # Example: Remove trailing whitespace if configured
    if config.get('remove_trailing_whitespace', False):
        result = '\n'.join(line.rstrip() for line in result.splitlines())

    # Example: Standardize line endings
    if config.get('line_ending') == 'lf':
        result = result.replace('\r\n', '\n')
    elif config.get('line_ending') == 'crlf':
        result = result.replace('\n', '\r\n')

    # Add more formatting rules as needed
    return result

def is_valid_extension(filepath: Path, allowed_extensions: List[str]) -> bool:
    """Check if file has an allowed extension."""
    return filepath.suffix.lower() in allowed_extensions

def process_file(filepath: Path, config: Dict[str, Any]) -> None:
    """Process a single file according to formatting rules."""
    # Skip files with extensions not in the allowed list
    allowed_extensions = config.get('extensions', ['.py', '.js', '.html', '.css'])
    if not is_valid_extension(filepath, allowed_extensions):
        return

    try:
        # Create backup
        if config.get('create_backup', True):
            backup_path = filepath.with_suffix(filepath.suffix + '.bak')
            shutil.copy2(filepath, backup_path)

        with filepath.open('r', encoding='utf-8') as f:
            contents = f.read()

        new_contents = reformat(contents, config)

        # Only write if content actually changed
        if new_contents != contents:
            with filepath.open('w', encoding='utf-8') as f:
                f.write(new_contents)
            print(f"Reformatted: {filepath}")
    except Exception as e:
        print(f"Error processing {filepath}: {e}")

def walk_dir(dirpath: Path, config: Dict[str, Any]) -> None:
    """Walk directory and process files."""
    # Get exclusion patterns
    exclude_dirs = set(config.get('exclude_dirs', ['.git', '.venv', 'node_modules']))

    for entry in os.scandir(dirpath):
        path = Path(entry.path)
        if entry.is_file():
            process_file(path, config)
        elif entry.is_dir() and path.name not in exclude_dirs:
            walk_dir(path, config)

if __name__ == '__main__':
    config = load_config()
    walk_dir(SOURCE_DIR, config)
    print("Formatting completed.")

