def course_registration():
    if 'user_id' not in session:
        return redirect(url_for('login'))

    if request.method == 'POST':
        course_code = request.form.get('course_code')

        if not course_code:
            flash('Course code is required')
            return redirect(url_for('course_registration'))

        # Validate course code format (example: CS101)
        if not re.match(r'^[A-Z]{2}\d{3}$', course_code):
            flash('Invalid course code format. It should be like CS101')
            return redirect(url_for('course_registration'))

        conn = get_db_connection()

        # Check if course exists
        course = conn.execute('SELECT * FROM courses WHERE course_code = ?', (course_code,)).fetchone()
        if not course:
            conn.close()
            flash('Course not found')
            return redirect(url_for('course_registration'))

        # Check if course has reached capacity
        enrollments_count = conn.execute(
            'SELECT COUNT(*) FROM enrollments WHERE course_id = ?', 
            (course['id'],)
        ).fetchone()[0]

        if enrollments_count >= course['max_capacity']:
            conn.close()
            flash('Course has reached maximum capacity')
            return redirect(url_for('course_registration'))

        # Check if student is already enrolled
        existing_enrollment = conn.execute(
            'SELECT * FROM enrollments WHERE student_id = ? AND course_id = ?',
            (session['user_id'], course['id'])
        ).fetchone()

        if existing_enrollment:
            conn.close()
            flash('You are already enrolled in this course')
            return redirect(url_for('course_registration'))

        # Enroll student in course
        try:
            conn.execute(
                'INSERT INTO enrollments (student_id, course_id) VALUES (?, ?)',
                (session['user_id'], course['id'])
            )
            conn.commit()
            flash(f'Successfully enrolled in {course["course_code"]}: {course["course_name"]}')
        except sqlite3.Error as e:
            flash(f'Error enrolling in course: {e}')
        finally:
            conn.close()

        return redirect(url_for('course_registration'))

    # Get courses available for registration
    conn = get_db_connection()
    available_courses = conn.execute('''
        SELECT c.*, 
               (SELECT COUNT(*) FROM enrollments WHERE course_id = c.id) as enrolled,
               c.max_capacity - (SELECT COUNT(*) FROM enrollments WHERE course_id = c.id) as seats_left
        FROM courses c
        WHERE c.max_capacity > (SELECT COUNT(*) FROM enrollments WHERE course_id = c.id)
    ''').fetchall()

    # Get student's enrolled courses
    enrolled_courses = conn.execute('''
        SELECT c.*
        FROM courses c
        JOIN enrollments e ON c.id = e.course_id
        WHERE e.student_id = ?
    ''', (session['user_id'],)).fetchall()

    conn.close()

    return render_template(
        'course_registration.html',
        available_courses=available_courses,
        enrolled_courses=enrolled_courses,
        student_name=session['name'],
        student_id=session['student_id']
    )

