        tar = tarfile.open("backup.tar", "w")
        tar.add(path, arcname=os.path.basename(path))
        tar.close()
        print(f"Backup of {path} created successfully")
    except Exception as e:
        print(f"Backup failed: {str(e)}")

def restore(path, tar_path):
    # Validate inputs
    if not os.path.exists(tar_path):
        raise ValueError(f"Tar file {tar_path} does not exist")
    if not os.path.exists(path):
        os.makedirs(path)

    # Check tar file is valid before removing anything
    try:
        tar = tarfile.open(tar_path, "r")
        # Create a safe temporary directory for extraction
        temp_dir = f"{path}_temp_restore"
        if os.path.exists(temp_dir):
            shutil.rmtree(temp_dir)
        os.makedirs(temp_dir)

        # Safely extract files to temp directory first
        for member in tar.getmembers():
            # Security check: ensure no path traversal
            member_path = os.path.join(temp_dir, member.name)
            if not os.path.abspath(member_path).startswith(os.path.abspath(temp_dir)):
                raise ValueError(f"Attempted path traversal in tar: {member.name}")
            tar.extract(member, temp_dir)

        # Now that extraction was successful, clear the target directory
        for f in os.listdir(path):
            file_path = os.path.join(path, f)
            if os.path.isfile(file_path):
                os.remove(file_path)
            elif os.path.isdir(file_path):
                shutil.rmtree(file_path)

        # Move extracted content to target directory
        extracted_dir = os.path.join(temp_dir, os.path.basename(path))
        for item in os.listdir(extracted_dir):
            shutil.move(os.path.join(extracted_dir, item), path)

        # Clean up temp directory
        shutil.rmtree(temp_dir)
        tar.close()
        print(f"Restore to {path} completed successfully")
    except Exception as e:
        print(f"Restore failed: {str(e)}")
        raise

if __name__ == "__main__":
    backup("/home/user/Documents")
    restore("/home/user/Documents", "backup.tar")

