def change_password(old_password, new_password):
    import bcrypt
    import re

    # Load the stored password hash from secure storage
    # This is just a placeholder - in a real app, you'd retrieve from a secure database
    try:
        with open('password_hash.dat', 'rb') as f:
            stored_hash = f.read()
    except FileNotFoundError:
        return "Error: Password data not found"

    # Verify the old password
    if not bcrypt.checkpw(old_password.encode(), stored_hash):
        return "Incorrect old password!"

    # Check if new password matches old password
    if new_password == old_password:
        return "New password cannot be the same as old password!"

    # Check password length
    if len(new_password) < 8:
        return "New password must be at least 8 characters!"

    # Check password complexity
    if not re.search(r'[A-Z]', new_password):
        return "Password must contain at least one uppercase letter!"
    if not re.search(r'[a-z]', new_password):
        return "Password must contain at least one lowercase letter!"
    if not re.search(r'[0-9]', new_password):
        return "Password must contain at least one number!"
    if not re.search(r'[^A-Za-z0-9]', new_password):
        return "Password must contain at least one special character!"

    # Generate a new salt and hash the new password
    salt = bcrypt.gensalt()
    new_hash = bcrypt.hashpw(new_password.encode(), salt)

    # Save the new password hash securely
    try:
        with open('password_hash.dat', 'wb') as f:
            f.write(new_hash)
        return "Password changed!"
    except Exception as e:
        return f"Error saving new password: {str(e)}"

