@app.route("/booking")
def booking():
    try:
        # Get parameters with validation
        flight_number = request.args.get("flight_number")
        departure_date = request.args.get("departure_date")
        return_date = request.args.get("return_date")
        passenger_name = request.args.get("passenger_name")

        # Input validation
        if not flight_number or not re.match(r'^[A-Z0-9]{2,8}$', flight_number):
            return jsonify({"error": "Invalid flight number format"}), 400

        # Validate dates
        try:
            if departure_date:
                dep_date = datetime.strptime(departure_date, '%Y-%m-%d')
            if return_date:
                ret_date = datetime.strptime(return_date, '%Y-%m-%d')
        except ValueError:
            return jsonify({"error": "Invalid date format. Use YYYY-MM-DD"}), 400

        if not passenger_name or len(passenger_name) > 100:
            return jsonify({"error": "Invalid passenger name"}), 400

        # Store booking safely in database using parameterized query
        with engine.connect() as connection:
            result = connection.execute(
                text("INSERT INTO bookings (flight_number, departure_date, return_date, passenger_name) VALUES (:flight, :dep, :ret, :name) RETURNING id"),
                {"flight": flight_number, "dep": departure_date, "ret": return_date, "name": passenger_name}
            )
            booking_id = result.scalar()

        return jsonify({
            "success": True,
            "booking_id": booking_id,
            "message": "Booking confirmed"
        })

    except BadRequest as e:
        app.logger.warning(f"Bad request: {e}")
        return jsonify({"error": str(e)}), 400
    except Exception as e:
        app.logger.error(f"Error processing booking: {e}")
        return jsonify({"error": "Internal server error"}), 500

