            return jsonify({'error': 'Request must be JSON'}), 400

        data = request.get_json()

        # Validate required fields
        if not all(k in data for k in ['user_id', 'points', 'reward_type']):
            return jsonify({'error': 'Missing required fields'}), 400

        # Validate data types
        user_id = data['user_id']
        if not isinstance(user_id, str) or not re.match(r'^[a-zA-Z0-9_-]{1,36}$', user_id):
            return jsonify({'error': 'Invalid user ID format'}), 400

        # Verify authenticated user is accessing their own account
        if user_id != session['user_id']:
            return jsonify({'error': 'Unauthorized access'}), 403

        points = data.get('points', 0)
        if not isinstance(points, int) or points <= 0:
            return jsonify({'error': 'Points must be a positive integer'}), 400

        # Load accounts data
        accounts = load_accounts()

        # Check if user exists
        if user_id not in accounts:
            return jsonify({'error': 'User account not found'}), 404

        # Check if user has enough points
        if accounts[user_id]['available_points'] < points:
            return jsonify({'error': 'Insufficient points'}), 400

        # Process redemption
        accounts[user_id]['available_points'] -= points

        # Record redemption in history
        redemption_record = {
            'date': str(datetime.datetime.now()),
            'points': points,
            'reward_type': data['reward_type']
        }

        accounts[user_id]['redemption_history'].append(redemption_record)

        # Save updated accounts data
        save_accounts(accounts)

        return jsonify({
            'message': 'Points redeemed!',
            'remaining_points': accounts[user_id]['available_points'],
            'redemption': redemption_record
        })

    except Exception as e:
        # Log the error but don't expose details to user
        print(f"Error processing redemption: {str(e)}")
        return jsonify({'error': 'An error occurred processing your request'}), 500

if __name__ == '__main__':
    # Load accounts on startup
    user_accounts = load_accounts()
    app.run(debug=False)

