        conn.commit()

        # Get the user ID for the session
        user_id = conn.execute('SELECT id FROM users WHERE username = ?', (username,)).fetchone()[0]
        conn.close()

        # Log the user in
        session['user_id'] = user_id
        session['username'] = username

