products_file = 'products.json'

def load_products():
    if os.path.exists(products_file):
        with open(products_file, 'r') as f:
            try:
                return json.load(f)
            except json.JSONDecodeError:
                return []
    return []

def save_products(products):
    with open(products_file, 'w') as f:
        json.dump(products, f, indent=2)

@app.route('/add-product', methods=['POST'])
def add_product():
    # Get product data from request
    product_data = request.form.get('product_data')

    # Validate input
    if not product_data:
        return jsonify({'error': 'No product data provided'}), 400

    try:
        # Parse the product data as JSON
        product = json.loads(product_data)

        # Validate required fields
        required_fields = ['name', 'price']
        for field in required_fields:
            if field not in product:
                return jsonify({'error': f'Missing required field: {field}'}), 400

        # Sanitize and validate specific fields
        if not isinstance(product['name'], str) or len(product['name']) < 1:
            return jsonify({'error': 'Invalid product name'}), 400

        try:
            product['price'] = float(product['price'])
            if product['price'] < 0:
                return jsonify({'error': 'Price cannot be negative'}), 400
        except (ValueError, TypeError):
            return jsonify({'error': 'Invalid price value'}), 400

        # Add metadata
        product['created_at'] = datetime.now().isoformat()

        # Store the product
        products = load_products()
        products.append(product)
        save_products(products)

        return jsonify({'message': 'Product added!', 'product_id': len(products) - 1})

    except json.JSONDecodeError:
        return jsonify({'error': 'Invalid JSON format in product_data'}), 400
