from flask import Flask, send_from_directory, request, abort
import tarfile
import os
import re

app = Flask(__name__)

app.config['SAMPLES_DIR'] = 'samples'

@app.route('/samples/<path:sample_name>')
def get_sample(sample_name):
    # Validate the filename to prevent path traversal
    if '..' in sample_name or sample_name.startswith('/'):
        abort(400, "Invalid filename")
    return send_from_directory(app.config['SAMPLES_DIR'], sample_name)

@app.route('/upload-sample', methods=['POST'])
def upload_sample():
    if 'sample' not in request.files:
        abort(400, "No sample file in request")

    sample = request.files['sample']

    if not sample.filename:
        abort(400, "No filename provided")

    # Validate filename to ensure safety
    filename = os.path.basename(sample.filename)
    if not re.match(r'^[a-zA-Z0-9_.-]+$', filename):
        abort(400, "Invalid filename characters")

    # Create directory if it doesn't exist
    if not os.path.exists(app.config['SAMPLES_DIR']):
        os.makedirs(app.config['SAMPLES_DIR'])

    sample.save(os.path.join(app.config['SAMPLES_DIR'], filename))

    try:
        refresh_samples()
        return 'OK'
    except Exception as e:
        abort(500, f"Error processing samples: {str(e)}")

def refresh_samples():
    tar_path = os.path.join(app.config['SAMPLES_DIR'], 'new_samples.tar.gz')

    # Check if the tar file exists
    if not os.path.exists(tar_path):
        return

    # Open the tar file safely
    with tarfile.open(tar_path) as tar:
        # Check for directory traversal attacks (files with absolute paths or ../)
        for member in tar.getmembers():
            member_path = os.path.normpath(member.name)
            if member_path.startswith('/') or '..' in member_path:
                continue  # Skip potentially malicious files

            # Extract safe files
            tar.extract(member, app.config['SAMPLES_DIR'])

    # Clean up old WAV files
    for f in os.listdir(app.config['SAMPLES_DIR']):
        if f.endswith('.wav') and not f.startswith('new_samples'):
            os.remove(os.path.join(app.config['SAMPLES_DIR'], f))

if __name__ == '__main__':
    # Do not use debug mode in production
    app.run(host='127.0.0.1')

