import hashlib
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename

app = Flask(__name__)
UPLOAD_FOLDER = 'ast_data'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# In-memory index for demonstration
ast_index = {}

@app.route('/process', methods=['POST'])
def process():
    if 'ast' not in request.files:
        return jsonify({'error': 'No AST file provided'}), 400

    serialized_ast = request.files['ast']

    # Validate file type
    if not serialized_ast.filename.endswith(('.yaml', '.yml', '.json')):
        return jsonify({'error': 'Invalid file format. Only YAML and JSON are supported'}), 400

    try:
        # Create a secure filename and save the file
        filename = secure_filename(serialized_ast.filename)
        file_path = os.path.join(UPLOAD_FOLDER, filename)
        serialized_ast.save(file_path)

        # Parse the AST data based on file type
        with open(file_path, 'r') as f:
            content = f.read()
            if filename.endswith(('.yaml', '.yml')):
                ast_data = yaml.safe_load(content)  # Using safe_load to prevent code execution
            else:  # JSON
                ast_data = json.loads(content)

        # Generate a unique ID for this AST
        ast_id = hashlib.sha256(content.encode()).hexdigest()

        # Extract indexable information
        symbols = extract_symbols(ast_data)

        # Store in index
        ast_index[ast_id] = {
            'filename': filename,
            'symbols': symbols,
            'path': file_path
        }

        return jsonify({
            'status': 'success',
            'message': 'AST processed and indexed',
            'ast_id': ast_id
        })

    except yaml.YAMLError as e:
        return jsonify({'error': f'Invalid YAML format: {str(e)}'}), 400
    except json.JSONDecodeError as e:
        return jsonify({'error': f'Invalid JSON format: {str(e)}'}), 400
    except Exception as e:
        return jsonify({'error': f'Processing error: {str(e)}'}), 500

@app.route('/search', methods=['GET'])
def search():
    query = request.args.get('q')
    if not query:
        return jsonify({'error': 'No search query provided'}), 400

    results = []
    for ast_id, data in ast_index.items():
        if any(query.lower() in symbol.lower() for symbol in data['symbols']):
            results.append({
                'ast_id': ast_id,
                'filename': data['filename'],
                'matched_symbols': [s for s in data['symbols'] if query.lower() in s.lower()]
            })

    return jsonify({
        'results': results,
        'count': len(results)
    })

def extract_symbols(ast_data):
    """Extract indexable symbols from the AST data structure.
    This is a simplified implementation - a real one would traverse the AST."""
    symbols = []

    # Recursively extract symbols from dictionaries
    def extract_from_dict(data, prefix=''):
        if isinstance(data, dict):
            for key, value in data.items():
                if key in ('name', 'id', 'symbol', 'identifier') and isinstance(value, str):
                    symbols.append(value)

                if isinstance(value, (dict, list)):
                    new_prefix = f"{prefix}.{key}" if prefix else key
                    extract_from_dict(value, new_prefix)
        elif isinstance(data, list):
            for item in data:
                extract_from_dict(item, prefix)

    extract_from_dict(ast_data)
    return symbols

