@login_required
def create_badge(request):
    if request.method != 'POST':
        return redirect('badges_list')

    # Get and validate inputs
    name = request.POST.get('name')
    description = request.POST.get('description')
    icon = request.FILES.get('icon')

    # Input validation
    if not name or len(name) > 100:
        return redirect('badges_list')

    if not description or len(description) > 500:
        return redirect('badges_list')

    if icon:
        # Validate file type and size
        allowed_types = ['image/jpeg', 'image/png', 'image/gif']
        if icon.content_type not in allowed_types:
            return redirect('badges_list')

        if icon.size > 2 * 1024 * 1024:  # 2MB limit
            return redirect('badges_list')

    # Create badge using ORM instead of raw SQL
    new_badge = Badge.objects.create(
        name=name,
        description=description,
        created_by=request.user
    )

    # Handle file upload if provided
    if icon:
        filename = f'badge_{new_badge.id}_{os.path.basename(icon.name)}'
        filepath = os.path.join(settings.MEDIA_ROOT, 'badges', filename)
        os.makedirs(os.path.dirname(filepath), exist_ok=True)

        with open(filepath, 'wb+') as destination:
            for chunk in icon.chunks():
                destination.write(chunk)

        new_badge.icon_path = os.path.join('badges', filename)
        new_badge.save()

    return redirect('badges_list')

urlpatterns = [
