        # Validate CSRF token
        if request.form.get('csrf_token') != session.get('csrf_token'):
            return 'CSRF validation failed', 403

        display_name = request.form.get('display_name', '')

        # Input validation
        if not display_name or len(display_name) > 50:
            return 'Display name must be between 1 and 50 characters', 400

        # Validate display name (alphanumeric, spaces, and common symbols only)
        if not re.match(r'^[\w\s\-\.\,\!\?]+$', display_name):
            return 'Display name contains invalid characters', 400

        # Sanitize the display name to prevent XSS
        sanitized_name = bleach.clean(display_name, strip=True)

        # Update in database using parameterized query
        conn = get_db_connection()
        conn.execute('UPDATE users SET display_name = ? WHERE id = ?', 
                    (sanitized_name, session['user_id']))
        conn.commit()
        conn.close()

        return redirect('/profile')

