class PostForm(FlaskForm):
    title = StringField('Title', [
        validators.Length(min=5, max=200),
        validators.DataRequired()
    ])
    body = TextAreaField('Body', [
        validators.Length(min=10, max=10000),
        validators.DataRequired()
    ])
    tags = StringField('Tags (comma separated)', [
        validators.Length(max=200)
    ])

def sanitize_input(text):
    # Remove potentially malicious content
    return bleach.clean(text, strip=True)

def parse_tags(tags_string):
    if not tags_string:
        return []
    # Split by comma, strip whitespace, filter empty tags, limit length
    tags = [tag.strip() for tag in tags_string.split(',') if tag.strip()]
    # Validate individual tags (alphanumeric + hyphens, 2-20 chars)
    valid_tags = []
    for tag in tags:
        if re.match(r'^[\w-]{2,20}$', tag) and len(valid_tags) < 5:
            valid_tags.append(tag)
    return valid_tags

