            clean_title = sanitize_input(form.title.data)
            clean_body = sanitize_input(form.body.data)

            # Process tags
            tag_names = parse_tags(form.tags.data)
            post_tags = []

            # Get or create tags
            for tag_name in tag_names:
                tag = Tag.query.filter_by(name=tag_name).first()
                if not tag:
                    tag = Tag(name=tag_name)
                    db.session.add(tag)
                post_tags.append(tag)

            # Create new post
            new_post = Post(
                title=clean_title,
                body=clean_body,
                user_id=session['user_id']
            )

            # Add tags to post
            new_post.tags = post_tags

            # Save to database
            db.session.add(new_post)
            db.session.commit()

            flash('Post created successfully!')
            return redirect(url_for('view_post', post_id=new_post.id))

        except Exception as e:
            db.session.rollback()
            flash(f'Error creating post: {str(e)}')

    return render_template('create_post.html', form=form)

if __name__ == '__main__':
