    # First, check if the user is the owner of the tutorial
    cursor.execute('SELECT user_id, filename FROM tutorials WHERE id = ?', (tutorial_id,))
    tutorial = cursor.fetchone()

    if not tutorial:
        conn.close()
        flash('Tutorial not found')
        return redirect(url_for('home'))

    if tutorial[0] != session['user_id']:
        conn.close()
        flash('You can only delete your own tutorials')
