# Example of interacting with Git version control in Python
import git
import os
import logging
from pathlib import Path

# Set up logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class GitManager:
    def __init__(self, repo_path=None):
        """Initialize the Git manager with a repository path"""
        self.repo = None
        if repo_path:
            self.open_repository(repo_path)

    def open_repository(self, repo_path):
        """Open an existing Git repository"""
        try:
            repo_path = Path(repo_path).resolve()
            if not repo_path.exists():
                raise ValueError(f"Repository path does not exist: {repo_path}")

            self.repo = git.Repo(repo_path)
            logger.info(f"Opened repository at {repo_path}")
        except git.GitCommandError as e:
            logger.error(f"Git command error: {e}")
            raise
        except Exception as e:
            logger.error(f"Error opening repository: {e}")
            raise

    def clone_repository(self, url, target_path, branch=None):
        """Clone a repository from URL to target path"""
        try:
            # Validate the target path
            target_path = Path(target_path).resolve()
            if target_path.exists() and any(target_path.iterdir()):
                raise ValueError(f"Target directory is not empty: {target_path}")

            # Clone the repository
            logger.info(f"Cloning repository from {url} to {target_path}")
            if branch:
                self.repo = git.Repo.clone_from(url, target_path, branch=branch)
            else:
                self.repo = git.Repo.clone_from(url, target_path)

            logger.info(f"Repository cloned successfully")
            return True
        except git.GitCommandError as e:
            logger.error(f"Git command error during clone: {e}")
            raise
        except Exception as e:
            logger.error(f"Error during clone: {e}")
            raise

    def commit_changes(self, message, files=None):
        """Commit changes to the repository"""
        if not self.repo:
            raise ValueError("No repository is currently open")

        try:
            # Stage files or stage all if files is None
            if files:
                for file_path in files:
                    # Validate each file exists before adding
                    if not Path(self.repo.working_dir, file_path).exists():
                        raise ValueError(f"File does not exist: {file_path}")
                    self.repo.git.add(file_path)
            else:
                self.repo.git.add('--all')

            # Create commit with the specified message
            if not message or not message.strip():
                raise ValueError("Commit message cannot be empty")

            self.repo.index.commit(message)
            logger.info(f"Changes committed with message: {message}")
            return True
        except git.GitCommandError as e:
            logger.error(f"Git command error during commit: {e}")
            raise
        except Exception as e:
            logger.error(f"Error during commit: {e}")
            raise

    def push_changes(self, remote='origin', branch='master'):
        """Push commits to the remote repository"""
        if not self.repo:
            raise ValueError("No repository is currently open")

        try:
            # Validate remote exists
            if remote not in [r.name for r in self.repo.remotes]:
                raise ValueError(f"Remote '{remote}' does not exist")

            # Get the remote and push
            origin = self.repo.remotes[remote]
            push_info = origin.push(branch)

            # Check for errors in push_info
            for info in push_info:
                if info.flags & info.ERROR:
                    raise git.GitCommandError(f"Push failed: {info.summary}")

            logger.info(f"Changes pushed to {remote}/{branch}")
            return True
        except git.GitCommandError as e:
            logger.error(f"Git command error during push: {e}")
            raise
        except Exception as e:
            logger.error(f"Error during push: {e}")
            raise

# Example usage
def main():
    try:
        # Create a GitManager instance
        git_manager = GitManager()

        # Clone a repository
        git_manager.clone_repository(
            "https://github.com/example/repo.git", 
            "./local_repo"
        )

        # Open an existing repository
        # git_manager.open_repository("./existing_repo")

        # Make some changes to files...
        # Then commit and push those changes
        # git_manager.commit_changes("Update documentation")
        # git_manager.push_changes()

        logger.info("Git operations completed successfully")
    except Exception as e:
        logger.error(f"Error in main: {e}")

if __name__ == "__main__":
    main()

