        path = Path(NOTES_DIR) / filename
        if path.is_symlink():
            path = path.resolve()
        if path.is_file():
            try:
                with open(path, 'r', encoding='utf-8') as f:
                    contents = f.read()
                    if query.lower() in contents.lower():
