import os
import sys
from pathlib import Path
import shutil
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def find_large_files(path, min_size):
    """Find files larger than min_size bytes in the given path."""
    large_files = []
    try:
        for f in path.glob('**/*'):
            try:
                if f.is_file() and f.stat().st_size > min_size:
                    large_files.append(f)
            except (PermissionError, OSError) as e:
                logging.warning(f"Cannot access {f}: {e}")
    except Exception as e:
        logging.error(f"Error scanning directory {path}: {e}")

    return large_files

def move_large_files(files, dest_dir):
    """Move files to the destination directory with proper error handling."""
    # Create destination directory if it doesn't exist
    dest_path = Path(dest_dir)
    try:
        dest_path.mkdir(exist_ok=True, parents=True)
    except OSError as e:
        logging.error(f"Cannot create destination directory {dest_dir}: {e}")
        return

    moved_count = 0
    for f in files:
        try:
            filename = f.name
            target_path = dest_path / filename

            # Handle duplicate filenames
            counter = 1
            while target_path.exists():
                name_parts = filename.rsplit('.', 1)
                if len(name_parts) > 1:
                    new_name = f"{name_parts[0]}_{counter}.{name_parts[1]}"
                else:
                    new_name = f"{filename}_{counter}"
                target_path = dest_path / new_name
                counter += 1

            # Use shutil.move which is safer than os.rename for cross-device moves
            shutil.move(str(f), str(target_path))
            logging.info(f"Moved: {f} -> {target_path}")
            moved_count += 1
        except (PermissionError, OSError) as e:
            logging.error(f"Failed to move {f}: {e}")

    logging.info(f"Successfully moved {moved_count} files to {dest_dir}")

def parse_size(size_str):
    """Convert human-readable size to bytes."""
    units = {'B': 1, 'K': 1024, 'M': 1024**2, 'G': 1024**3, 'T': 1024**4}
    if size_str[-1] in units:
        return int(float(size_str[:-1]) * units[size_str[-1]])
    return int(size_str)

if __name__ == '__main__':
    # Use a safer default path than root
    default_path = str(Path.home())
    default_min_size = 100000000  # 100MB

    # Allow command line arguments
    if len(sys.argv) > 1:
        scan_path = sys.argv[1]
    else:
        scan_path = input(f"Enter path to scan [default: {default_path}]: ") or default_path

    min_size_input = input(f"Enter minimum file size in bytes or with unit (e.g., 100M) [default: 100M]: ") or "100M"
    try:
        min_size = parse_size(min_size_input)
    except ValueError:
        logging.error(f"Invalid size format: {min_size_input}")
        sys.exit(1)

    dest_dir = input("Enter destination directory for large files [default: large_files]: ") or "large_files"

    try:
        path = Path(scan_path).resolve()
        if not path.exists():
            logging.error(f"Path does not exist: {path}")
            sys.exit(1)

        logging.info(f"Scanning {path} for files larger than {min_size} bytes...")
        large_files = find_large_files(path, min_size)
        logging.info(f"Found {len(large_files)} large files")

        if large_files:
            confirm = input(f"Move {len(large_files)} files to {dest_dir}? (y/n): ").lower()
            if confirm == 'y':
                move_large_files(large_files, dest_dir)
            else:
                logging.info("Operation cancelled by user")
    except KeyboardInterrupt:
        logging.info("Operation cancelled by user")
    except Exception as e:
        logging.error(f"Unexpected error: {e}")

