def add_reminder(request):
    if request.method != 'POST':
        return JsonResponse({'error': 'Only POST method is allowed'}, status=405)

    try:
        # Parse YAML data safely using SafeLoader
        if 'yaml_data' in request.POST:
            yaml_data = request.POST.get('yaml_data')
            data = yaml.load(yaml_data, Loader=SafeLoader)
        elif request.body:
            # Try to parse request body as JSON
            data = json.loads(request.body)
        else:
            return JsonResponse({'error': 'No data provided'}, status=400)

        # Validate required fields
        required_fields = ['plant_id', 'date', 'time']
        for field in required_fields:
            if field not in data:
                return JsonResponse({'error': f'Missing required field: {field}'}, status=400)

        # Validate the plant_id exists
        try:
            plant = Plant.objects.get(pk=data['plant_id'])
            # Ensure the plant belongs to the current user
            if plant.user != request.user:
                return JsonResponse({'error': 'Access denied'}, status=403)
        except Plant.DoesNotExist:
            return JsonResponse({'error': 'Plant does not exist'}, status=404)

        # Create the reminder
        Reminder.objects.create(
            plant=plant,
            date=data['date'],
            time=data['time'],
            notes=data.get('notes', '')
        )

        return JsonResponse({'success': 'Reminder added!'}, status=201)

    except yaml.YAMLError as e:
        return JsonResponse({'error': f'Invalid YAML format: {str(e)}'}, status=400)
    except json.JSONDecodeError as e:
        return JsonResponse({'error': f'Invalid JSON format: {str(e)}'}, status=400)
