import glob, os
import logging
from pathlib import Path
from PIL import Image
from PIL.ExifTags import TAGS

def get_exif(fname):
    try:
        image = Image.open(fname)
        exif_data = image._getexif()
        if not exif_data:
            return {}
        return {TAGS.get(tag, tag): value for tag, value in exif_data.items()}
    except (AttributeError, IOError, KeyError) as e:
        logging.warning(f"Could not extract EXIF data from {fname}: {e}")
        return {}

def rename_images(path):
    # Validate path exists
    if not os.path.isdir(path):
        logging.error(f"The path {path} does not exist or is not a directory")
        return

    # Create a set to track filenames and avoid duplicates
    used_names = set()

    # Process multiple image formats
    for extension in ('*.jpg', '*.jpeg', '*.png'):
        for fname in glob.glob(os.path.join(path, extension)):
            try:
                exif = get_exif(fname)

                # Skip if no EXIF data or missing date information
                if not exif or 'DateTimeOriginal' not in exif:
                    logging.info(f"No date information found for {fname}, skipping")
                    continue

                date = exif['DateTimeOriginal'].split(' ')[0].replace(':', '-')
                base_name = os.path.basename(fname)
                new_name = os.path.join(path, f"{date}_{base_name}")

                # Handle duplicate filenames
                counter = 1
                original_new_name = new_name
                while new_name in used_names or os.path.exists(new_name):
                    file_parts = os.path.splitext(original_new_name)
                    new_name = f"{file_parts[0]}_{counter}{file_parts[1]}"
                    counter += 1

                used_names.add(new_name)
                os.rename(fname, new_name)
                logging.info(f"Renamed {fname} to {new_name}")
            except Exception as e:
                logging.error(f"Error processing {fname}: {e}")

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# Use Path for safer path handling
def main(directory):
    path = Path(directory).resolve()
    rename_images(str(path))

if __name__ == "__main__":
    import sys
    if len(sys.argv) > 1:
        main(sys.argv[1])
    else:
        print("Please provide a directory path")

