import os
import stat
import datetime
import platform
import logging
from pathlib import Path

def get_file_metadata(path):
    """Safely retrieve file metadata including permissions."""
    try:
        file_path = Path(path).resolve()
        if not file_path.exists():
            return {"error": "File does not exist"}

        # Get basic file information
        stats = file_path.stat()

        # Format permissions in octal and human-readable format
        mode = stats.st_mode
        permissions_octal = oct(mode & 0o777)[2:]
        permissions_human = {
            "read": bool(mode & stat.S_IRUSR),
            "write": bool(mode & stat.S_IWUSR),
            "execute": bool(mode & stat.S_IXUSR),
            "owner": file_path.owner(),
            "group": file_path.group()
        }

        # Gather metadata
        metadata = {
            "name": file_path.name,
            "size": stats.st_size,
            "created": datetime.datetime.fromtimestamp(stats.st_ctime).isoformat(),
            "modified": datetime.datetime.fromtimestamp(stats.st_mtime).isoformat(),
            "accessed": datetime.datetime.fromtimestamp(stats.st_atime).isoformat(),
            "permissions": {
                "octal": permissions_octal,
                "details": permissions_human
            },
            "type": "directory" if file_path.is_dir() else "file",
            "extension": file_path.suffix,
            "is_symlink": file_path.is_symlink(),
            "absolute_path": str(file_path)
        }

        return metadata
    except PermissionError:
        return {"error": "Permission denied"}
    except Exception as e:
        logging.error(f"Error processing file {path}: {str(e)}")
        return {"error": str(e)}

def process_file(path):
    """Process file metadata for AR visualization without modifying it."""
    # Validate path
    if not path or not isinstance(path, str):
        return {"error": "Invalid path"}

    # Get metadata safely
    metadata = get_file_metadata(path)

    # Return metadata for AR visualization
    return {
        "metadata": metadata,
        "visualization_hints": {
            "read_color": "green" if metadata.get("permissions", {}).get("details", {}).get("read", False) else "red",
            "write_color": "yellow" if metadata.get("permissions", {}).get("details", {}).get("write", False) else "gray",
            "execute_color": "blue" if metadata.get("permissions", {}).get("details", {}).get("execute", False) else "gray",
            "size_scale": min(1.0, metadata.get("size", 0) / 1000000)  # Scale visualization based on file size
        }
    }

# Example usage (with a safe default path)
result = process_file(os.path.join(os.path.expanduser("~"), "Documents"))
print(result)

import os
import re
import uuid

def create_paste(contents):
    # Generate a random paste ID using UUID
    paste_id = str(uuid.uuid4())

    # Store the paste contents
    save_paste(paste_id, contents)
    return paste_id

def get_paste(paste_id):
    # Validate paste ID format to prevent path traversal
    if not is_valid_paste_id(paste_id):
        return None

    paste_path = os.path.join('/var/www/pastebin', paste_id)

    # Check if paste exists
    if not os.path.exists(paste_path):
        return None

    try:
        with open(paste_path, 'r') as f:
            return f.read()
    except Exception:
        return None

def update_paste(paste_id, new_contents):
    # Validate paste ID format to prevent path traversal
    if not is_valid_paste_id(paste_id):
        return False

    paste_path = os.path.join('/var/www/pastebin', paste_id)

    # Check if paste exists before updating
    if not os.path.exists(paste_path):
        return False

    try:
        with open(paste_path, 'w') as f:
            f.write(new_contents)
        return True
    except Exception:
        return False

def delete_paste(paste_id):
    # Validate paste ID format to prevent path traversal
    if not is_valid_paste_id(paste_id):
        return False

    paste_path = os.path.join('/var/www/pastebin', paste_id)

    # Check if paste exists before deleting
    if not os.path.exists(paste_path):
        return False

    try:
        os.remove(paste_path)
        return True
    except Exception:
        return False

def save_paste(paste_id, contents):
    paste_path = os.path.join('/var/www/pastebin', paste_id)

    with open(paste_path, 'w') as f:
        f.write(contents)

    return True

def is_valid_paste_id(paste_id):
    # Only allow alphanumeric characters and hyphens (for UUID format)
    return bool(re.match(r'^[a-zA-Z0-9\-]+$', paste_id))

