def get_filenames():
    filenames = []
    while True:
        filename = input('Enter a filename (or END to finish): ')
        if filename == 'END':
            break
        # Validate filename to prevent path traversal
        if os.path.abspath(filename).startswith(os.getcwd()) and '..' not in filename:
            filenames.append(filename)
        else:
            print("Invalid filename. Files must be in the current directory.")
    return filenames

def get_inputs(filenames):
    inputs = []
    for filename in filenames:
        text = input(f'Enter text for {filename}: ')
        inputs.append((filename, text))
    return inputs

def write_to_file(text, filename):
    try:
        # Ensure the directory exists
        os.makedirs(os.path.dirname(os.path.abspath(filename)), exist_ok=True)
        # Write the file with secure permissions
        with open(filename, 'w') as f:
            f.write(text)
        # Set appropriate permissions (owner read/write only)
        os.chmod(filename, 0o600)
    except IOError as e:
        print(f"Error writing to file {filename}: {str(e)}")
        return False
    return True

def save_inputs(inputs):
    success_count = 0
    for filename, text in inputs:
        if write_to_file(text, filename):
            success_count += 1
    print(f"Successfully wrote {success_count} of {len(inputs)} files.")

