        return -100 <= temp_float <= 100  # Reasonable temperature range in Celsius
    except (ValueError, TypeError):
        return False

def validate_conditions(conditions):
    allowed_conditions = ['sunny', 'cloudy', 'rainy', 'snowy', 'windy', 'stormy', 'foggy']
    return conditions.lower() in allowed_conditions

