from flask import Flask, request, jsonify
import requests
import os
from functools import wraps
import time
from dotenv import load_dotenv

load_dotenv()

app = Flask(__name__)

# Get API key from environment variables
API_KEY = os.environ.get('MOVIE_API_KEY')
API_BASE_URL = 'https://api.themoviedb.org/3'

# Dictionary to store request counts for rate limiting
request_counts = {}
RATE_LIMIT = 10  # requests per minute
TIME_WINDOW = 60  # seconds

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        ip = request.remote_addr
        current_time = time.time()

        # Initialize or clean old requests
        if ip not in request_counts:
            request_counts[ip] = []
        request_counts[ip] = [t for t in request_counts[ip] if current_time - t < TIME_WINDOW]

        # Check rate limit
        if len(request_counts[ip]) >= RATE_LIMIT:
            return jsonify({'error': 'Rate limit exceeded. Please try again later.'}), 429

        # Add timestamp and process request
        request_counts[ip].append(current_time)
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/movies/search', methods=['GET'])
@rate_limit
def search_movies():
    query = request.args.get('query', '')
    page = request.args.get('page', '1')

    # Input validation
    if not query:
        return jsonify({'error': 'Search query is required'}), 400

    try:
        page = int(page)
        if page < 1:
            return jsonify({'error': 'Page must be a positive integer'}), 400
    except ValueError:
        return jsonify({'error': 'Page must be a valid integer'}), 400

    try:
        # Make request to external API with proper parameter handling
        response = requests.get(
            f'{API_BASE_URL}/search/movie',
            params={
                'api_key': API_KEY,
                'query': query,
                'page': page
            }
        )

        # Check if the request was successful
        response.raise_for_status()

        # Return the data
        return jsonify(response.json())

    except requests.exceptions.RequestException as e:
        app.logger.error(f"API request error: {str(e)}")
        return jsonify({'error': 'Failed to fetch movie data'}), 500

@app.route('/api/movies/<int:movie_id>', methods=['GET'])
@rate_limit
def get_movie(movie_id):
    try:
        response = requests.get(
            f'{API_BASE_URL}/movie/{movie_id}',
            params={'api_key': API_KEY}
        )
        response.raise_for_status()
        return jsonify(response.json())

    except requests.exceptions.RequestException as e:
        app.logger.error(f"API request error: {str(e)}")
        return jsonify({'error': 'Failed to fetch movie details'}), 500

if __name__ == '__main__':
    # In production, use a proper WSGI server and HTTPS
    app.run(debug=False, host='0.0.0.0')

