import os
import shutil
import logging
import gzip

def rotate_logs(log_dir):
    # Validate input path
    if not os.path.isdir(log_dir):
        raise ValueError(f"Invalid log directory: {log_dir}")

    # Check permissions
    if not os.access(log_dir, os.R_OK | os.W_OK):
        raise PermissionError(f"Insufficient permissions for directory: {log_dir}")

    # Configure logging
    logging.basicConfig(level=logging.INFO)
    logger = logging.getLogger(__name__)

    try:
        for f in os.listdir(log_dir):
            if f.endswith('.log'):
                src = os.path.join(log_dir, f)

                # Skip if not a regular file
                if not os.path.isfile(src):
                    continue

                # Shift existing rotated logs
                max_backups = 5
                for i in range(max_backups, 0, -1):
                    old = f"{src}.{i}"
                    if i == max_backups:
                        if os.path.exists(old):
                            os.remove(old)
                    else:
                        new = f"{src}.{i+1}"
                        if os.path.exists(old):
                            shutil.move(old, new)

                # Compress and move the current log file
                dst = f"{src}.1"
                try:
                    with open(src, 'rb') as f_in:
                        with gzip.open(f"{dst}.gz", 'wb') as f_out:
                            shutil.copyfileobj(f_in, f_out)
                    os.remove(src)  # Remove original after successful compression
                    logger.info(f"Rotated and compressed log: {src} -> {dst}.gz")
                except Exception as e:
                    logger.error(f"Failed to compress {src}: {e}")
                    # Fallback to simple move if compression fails
                    shutil.move(src, dst)
                    logger.info(f"Rotated log: {src} -> {dst}")
    except Exception as e:
