def create_dir(path):
    try:
        os.mkdir(path)
    except FileExistsError:
        pass

def validate_path(path):
    """Validate that path is safe and doesn't contain path traversal attempts"""
    if not path or '..' in path or path.startswith('/'):
        raise ValueError("Invalid path provided")
    return os.path.abspath(os.path.join(os.getcwd(), path))

def get_coverage_data(project_path):
    """Run coverage tool and return results"""
    try:
        # Use a safe method to run coverage
        result = subprocess.run(
            ['coverage', 'run', '-m', 'pytest', project_path],
            capture_output=True,
            text=True,
            check=False
        )
        coverage_output = subprocess.run(
            ['coverage', 'report', '-m'],
            capture_output=True,
            text=True,
            check=False
        ).stdout
        return parse_coverage_output(coverage_output)
    except subprocess.SubprocessError as e:
        print(f"Error running coverage: {e}")
        return {}

def parse_coverage_output(output):
    """Parse coverage output to identify uncovered lines"""
    uncovered = {}
    lines = output.strip().split('\n')
    for line in lines[2:]:  # Skip header lines
        if line.strip():
            parts = re.split(r'\s+', line.strip())
            if len(parts) >= 5:
                file_path = parts[0]
                coverage_percent = float(parts[3].rstrip('%'))
                if coverage_percent < 100:
                    uncovered[file_path] = coverage_percent
    return uncovered

def annotate_uncovered_code(file_path, mode=0o644):
    """Add annotations to uncovered code"""
    try:
        # Run coverage annotation
        subprocess.run(
            ['coverage', 'annotate', file_path],
            check=False
        )

        # Set permissions on the annotated file
        annotated_file = file_path + ',cover'
        if os.path.exists(annotated_file):
            os.chmod(annotated_file, mode)
            print(f"Annotated file saved as {annotated_file} with permissions {oct(mode)}")
    except Exception as e:
        print(f"Error annotating file {file_path}: {e}")

def run_coverage_analyzer(project_path, output_dir, permissions=0o644):
    """Main function to analyze coverage and save annotations"""
    # Validate and sanitize inputs
    try:
        project_path = validate_path(project_path)

        # Create output directory with appropriate permissions
        create_dir(output_dir)
        os.chmod(output_dir, permissions)

        # Get coverage data
        uncovered_files = get_coverage_data(project_path)

        # Annotate uncovered code
        for file_path in uncovered_files:
            annotate_uncovered_code(file_path, permissions)

        # Generate report
        with open(os.path.join(output_dir, 'coverage_report.txt'), 'w') as f:
            f.write(f"Coverage Analysis Report\n")
            f.write(f"Found {len(uncovered_files)} files with incomplete coverage:\n")
            for file, coverage in uncovered_files.items():
                f.write(f"{file}: {coverage}%\n")

        # Set permissions on the report file
        os.chmod(os.path.join(output_dir, 'coverage_report.txt'), permissions)

        return True
    except Exception as e:
        print(f"Error analyzing coverage: {e}")
        return False

