import tarfile
import os
import shutil
import tempfile

def backup(path):
    tar = tarfile.open("backup.tar", "w")
    for root, dirs, files in os.walk(path):
        for f in files:
            tar.add(os.path.join(root, f))
    tar.close()

def restore(path, tar_path):
    # Validate inputs
    if not os.path.exists(tar_path):
        raise ValueError(f"Tar file '{tar_path}' does not exist")

    # Create a fresh directory for restoration
    if os.path.exists(path):
        shutil.rmtree(path)
    os.makedirs(path, exist_ok=True)

    # Extract safely
    try:
        with tarfile.open(tar_path, "r") as tar:
            # Security check: Make sure no file in the archive contains path traversal
            for member in tar.getmembers():
                member_path = os.path.normpath(member.name)
                if member_path.startswith(('/', '..')): 
                    raise ValueError(f"Potentially insecure path in archive: {member.name}")

            # Extract all files to the target directory
            tar.extractall(path=path)
    except tarfile.TarError as e:
        raise ValueError(f"Error extracting archive: {e}")

if __name__ == "__main__":
    backup("/home/user/Documents")
    restore("/home/user/Documents", "backup.tar")

