        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        return conn

    def update_survey(self, survey_id, name, description, owner_id):
        with self.get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "UPDATE surveys SET name = ?, description = ? WHERE id = ? AND owner_id = ?", 
                (name, description, survey_id, owner_id)
            )
            return cursor.rowcount > 0

    def get_survey(self, survey_id):
        with self.get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT * FROM surveys WHERE id = ?", (survey_id,))
            return cursor.fetchone()

