@app.route("/survey/<id>/edit", methods=["POST"])
def edit_survey(id):
    # Check if user is logged in
    if 'user_id' not in session:
        return redirect(url_for('login', next=request.path))

    # Verify CSRF token
    if request.form.get('csrf_token') != session.get('csrf_token'):
        abort(403, "CSRF token validation failed")

    # Get form data with validation
    name = request.form.get("name", "")
    description = request.form.get("description", "")

    # Validate inputs
    if not name or len(name) > 200:
        return render_template("edit_survey.html", error="Name is required and must be under 200 characters", survey_id=id)

    if len(description) > 1000:
        return render_template("edit_survey.html", error="Description must be under 1000 characters", survey_id=id)

    # Get survey to check ownership
    survey = db.get_survey(id)
    if not survey:
        abort(404, "Survey not found")

    # Check if user is the owner of the survey
    if survey['owner_id'] != session['user_id']:
        abort(403, "You don't have permission to edit this survey")

    # Update the survey
    success = db.update_survey(id, name, description, session['user_id'])

    message = "Survey updated successfully" if success else "No changes made to survey"
