from jinja2 import Template, escape

def render(template_str, **kwargs):
    # Create a template with autoescape enabled for security
    t = Template(template_str, autoescape=True)

    # Sanitize user inputs before rendering
    sanitized_kwargs = {}
    for key, value in kwargs.items():
        # Convert values to strings and escape if they're not already safe
        if isinstance(value, str):
            sanitized_kwargs[key] = value
        else:
            sanitized_kwargs[key] = str(value)

    try:
        # Render the template with sanitized inputs
        return t.render(**sanitized_kwargs)
    except Exception as e:
        # Log the error (in a real app) and return a safe fallback
        return f"Error rendering template: {escape(str(e))}"

from flask import Flask, request, jsonify
import json

app = Flask(__name__)

@app.route("/family_members")
def family_members():
    member_data = request.args.get('members')

    # Input validation
    if not member_data:
        return jsonify({"error": "No member data provided"}), 400

    try:
        # Parse the JSON data
        members = json.loads(member_data)

        # Validate the structure of the data
        if not isinstance(members, list):
            return jsonify({"error": "Member data must be a list"}), 400

        # Process and validate each member
        validated_members = []
        for member in members:
            if not isinstance(member, dict):
                continue

            # Validate required fields
            if 'name' not in member:
                continue

            # Sanitize and validate fields
            validated_member = {
                'name': str(member.get('name', ''))[:100],  # Limit name length
                'bio': str(member.get('bio', ''))[:500],  # Limit bio length
                'birthday': str(member.get('birthday', ''))[:20],
                'anniversary': str(member.get('anniversary', ''))[:20],
                'memories': str(member.get('memories', ''))[:1000],
                'photo_url': str(member.get('photo_url', ''))[:200]
            }
            validated_members.append(validated_member)

        return jsonify({
            "status": "success",
            "members": validated_members
        })
    except json.JSONDecodeError:
        return jsonify({"error": "Invalid JSON format"}), 400
    except Exception as e:
