import requests
from bs4 import BeautifulSoup
from urllib.parse import urljoin, urlparse
import time
from collections import deque
import robotparser

class WebCrawler:
    def __init__(self, start_url, max_pages=100, rate_limit=1):
        self.start_url = start_url
        self.max_pages = max_pages
        self.rate_limit = rate_limit  # seconds between requests
        self.visited_urls = set()
        self.url_queue = deque([start_url])
        self.site_map = {}

        # Setup for respecting robots.txt
        parsed_url = urlparse(start_url)
        self.base_url = f"{parsed_url.scheme}://{parsed_url.netloc}"
        self.rp = robotparser.RobotFileParser()
        self.rp.set_url(urljoin(self.base_url, '/robots.txt'))
        try:
            self.rp.read()
        except Exception as e:
            print(f"Warning: Could not read robots.txt: {e}")

    def is_valid_url(self, url):
        # Check if URL belongs to the same domain
        parsed_url = urlparse(url)
        parsed_base = urlparse(self.base_url)
        return parsed_url.netloc == parsed_base.netloc

    def is_allowed_by_robots(self, url):
        try:
            return self.rp.can_fetch("*", url)
        except Exception:
            # If we can't check robots.txt, assume it's allowed
            return True

    def crawl(self):
        count = 0

        while self.url_queue and count < self.max_pages:
            url = self.url_queue.popleft()

            if url in self.visited_urls:
                continue

            if not self.is_valid_url(url) or not self.is_allowed_by_robots(url):
                continue

            try:
                print(f"Crawling: {url}")
                response = requests.get(url, timeout=10, headers={'User-Agent': 'PythonCrawler/1.0'})

                # Only process pages with successful responses
                if response.status_code == 200:
                    self.visited_urls.add(url)
                    count += 1

                    # Parse content and extract links
                    soup = BeautifulSoup(response.text, 'html.parser')
                    links = []

                    for link in soup.find_all('a', href=True):
                        absolute_link = urljoin(url, link['href'])
                        # Remove fragments
                        absolute_link = absolute_link.split('#')[0]
                        if absolute_link and self.is_valid_url(absolute_link):
                            links.append(absolute_link)
                            if absolute_link not in self.visited_urls:
                                self.url_queue.append(absolute_link)

                    # Store found links in the site map
                    self.site_map[url] = links

                    # Rate limiting to be respectful
                    time.sleep(self.rate_limit)

            except Exception as e:
                print(f"Error crawling {url}: {e}")

        return self.site_map

def main():
    start_url = input("Enter the starting URL (including http/https): ")
    max_pages = int(input("Enter maximum number of pages to crawl: "))
    rate_limit = float(input("Enter rate limit in seconds between requests: "))

    crawler = WebCrawler(start_url, max_pages, rate_limit)
    site_map = crawler.crawl()

    print("\nCrawl completed! Site map:")
    for url, links in site_map.items():
        print(f"\n{url} links to:")
        for link in links:
            print(f"  - {link}")

if __name__ == "__main__":
    main()

