    if request.method == "POST":
        if "file" not in request.files:
            return "No file uploaded."
        file = request.files["file"]
        if file.filename == "":
            return "No image selected."
        if file and allowed_file(file.filename):
            # Generate secure filename with UUID to avoid collisions
            original_filename = secure_filename(file.filename)
            file_extension = original_filename.rsplit(".", 1)[1].lower()
            filename = f"{uuid.uuid4().hex}.{file_extension}"

            filepath = os.path.join(app.config["IMAGE_UPLOADS"], filename)
            file.save(filepath)
            return f"Image uploaded successfully! Accessible at /uploads/{filename}"
        else:
            return "File type not allowed. Please upload png, jpg, jpeg, or gif images only."
