import os
import argparse
import shutil
from pathlib import Path
import logging

# Set up logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

def get_file_size_mb(file_path):
    """Get file size in MB"""
    try:
        return os.path.getsize(file_path) / (1024 * 1024)
    except (OSError, FileNotFoundError) as e:
        logger.error(f"Error getting size of {file_path}: {e}")
        return 0

def analyze_directory(directory, size_threshold_mb):
    """Find files larger than the given threshold"""
    if not os.path.isdir(directory):
        logger.error(f"Directory {directory} does not exist.")
        return []

    large_files = []
    try:
        # Use Path for safer path handling
        for root, _, files in os.walk(directory):
            for filename in files:
                file_path = os.path.join(root, filename)
                # Skip symbolic links for safety
                if os.path.islink(file_path):
                    continue

                size_mb = get_file_size_mb(file_path)
                if size_mb >= size_threshold_mb:
                    large_files.append((file_path, size_mb))
    except Exception as e:
        logger.error(f"Error analyzing directory {directory}: {e}")

    return large_files

def change_permissions(file_path, permission_mode):
    """Change file permissions"""
    try:
        # Convert from string like '644' to octal
        if isinstance(permission_mode, str):
            permission_mode = int(permission_mode, 8)

        os.chmod(file_path, permission_mode)
        logger.info(f"Changed permissions of {file_path} to {oct(permission_mode)}")
        return True
    except Exception as e:
        logger.error(f"Error changing permissions of {file_path}: {e}")
        return False

def delete_file(file_path):
    """Safely delete a file"""
    try:
        # Extra safety check
        if not os.path.exists(file_path) or os.path.isdir(file_path):
            logger.error(f"Cannot delete: {file_path} is not a valid file")
            return False

        os.remove(file_path)
        logger.info(f"Deleted file: {file_path}")
        return True
    except Exception as e:
        logger.error(f"Error deleting {file_path}: {e}")
        return False

def main():
    parser = argparse.ArgumentParser(description='Analyze disk usage and manage large files.')
    parser.add_argument('directory', help='Directory to analyze')
    parser.add_argument('--threshold', type=float, default=100,
                        help='Size threshold in MB (default: 100)')
    parser.add_argument('--action', choices=['list', 'chmod', 'delete'],
                        default='list', help='Action to take on large files')
    parser.add_argument('--permissions', help='Permissions for chmod (e.g., 644)')

    args = parser.parse_args()

    # Validate directory is absolute and exists
    directory = os.path.abspath(args.directory)
    if not os.path.exists(directory):
        logger.error(f"Directory does not exist: {directory}")
        return

    logger.info(f"Analyzing directory: {directory}")
    logger.info(f"Finding files larger than {args.threshold} MB")

    large_files = analyze_directory(directory, args.threshold)

    if not large_files:
        logger.info("No large files found.")
        return

    logger.info(f"Found {len(large_files)} large files:")
    for file_path, size_mb in large_files:
        print(f"{file_path}: {size_mb:.2f} MB")

    if args.action == 'chmod':
        if not args.permissions:
            logger.error("Permissions required for chmod action.")
            return

        confirm = input(f"Change permissions of {len(large_files)} files to {args.permissions}? (y/n): ")
        if confirm.lower() == 'y':
            for file_path, _ in large_files:
                change_permissions(file_path, args.permissions)

    elif args.action == 'delete':
        confirm = input(f"Are you sure you want to delete {len(large_files)} files? (yes/no): ")
        if confirm.lower() != 'yes':
            logger.info("Deletion cancelled.")
            return

        for file_path, _ in large_files:
            delete_file(file_path)

