import os
import sys
from PIL import Image
from PIL.ExifTags import TAGS
import PyPDF2
import magic
import hashlib

def is_valid_file(file_path):
    """Validate if file exists and is a supported format."""
    if not os.path.exists(file_path) or not os.path.isfile(file_path):
        return False, "File does not exist or is not a regular file"

    # Use python-magic to detect file type safely
    mime = magic.Magic(mime=True)
    file_type = mime.from_file(file_path)

    if not (file_type.startswith('image/') or file_type.startswith('application/pdf')):
        return False, f"Unsupported file type: {file_type}"

    return True, file_type

def get_file_hash(file_path):
    """Generate SHA-256 hash of file for integrity verification."""
    sha256_hash = hashlib.sha256()
    with open(file_path, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest()

def extract_image_metadata(file_path):
    """Extract EXIF metadata from image files."""
    try:
        with Image.open(file_path) as img:
            metadata = {}
            if hasattr(img, '_getexif') and img._getexif():
                exif_data = img._getexif()
                if exif_data:
                    for tag_id, value in exif_data.items():
                        tag = TAGS.get(tag_id, tag_id)
                        metadata[tag] = value

            # Add basic image properties
            metadata['format'] = img.format
            metadata['mode'] = img.mode
            metadata['size'] = img.size
            return metadata
    except Exception as e:
        return {"error": f"Failed to extract image metadata: {str(e)}"}

def extract_pdf_metadata(file_path):
    """Extract metadata from PDF documents."""
    try:
        with open(file_path, 'rb') as file:
            reader = PyPDF2.PdfReader(file)
            metadata = reader.metadata
            if metadata:
                result = {}
                for key, value in metadata.items():
                    if key.startswith('/'):
                        result[key[1:]] = value
                    else:
                        result[key] = value
                result['pages'] = len(reader.pages)
                return result
            else:
                return {"info": "No metadata found in PDF"}
    except Exception as e:
        return {"error": f"Failed to extract PDF metadata: {str(e)}"}

def extract_metadata(file_path):
    """Main function to extract metadata from files."""
    # Validate input file
    valid, message = is_valid_file(file_path)
    if not valid:
        return {"error": message}

    # Get file hash for integrity verification
    file_hash = get_file_hash(file_path)

    # Get basic file information
    file_info = {
        "filename": os.path.basename(file_path),
        "size": os.path.getsize(file_path),
        "last_modified": os.path.getmtime(file_path),
        "sha256": file_hash
    }

    # Process based on file type
    if message.startswith('image/'):
        metadata = extract_image_metadata(file_path)
    elif message.startswith('application/pdf'):
        metadata = extract_pdf_metadata(file_path)
    else:
        metadata = {"error": "Unsupported file type"}

    # Combine file info with extracted metadata
    result = {"file_info": file_info, "metadata": metadata}
    return result

def main():
    if len(sys.argv) != 2:
        print("Usage: python metadata_analyzer.py <file_path>")
        sys.exit(1)

    file_path = sys.argv[1]
    result = extract_metadata(file_path)

    # Print results
    print("\nMetadata Analysis Result:")
    print("-" * 30)
    if "error" in result:
        print(f"Error: {result['error']}")
    else:
        print("File Information:")
        for key, value in result["file_info"].items():
            print(f"  {key}: {value}")

        print("\nExtracted Metadata:")
        if isinstance(result["metadata"], dict):
            for key, value in result["metadata"].items():
                print(f"  {key}: {value}")
        else:
            print(result["metadata"])

if __name__ == "__main__":
    main()

