from flask import Flask, request, render_template, jsonify
import re
import math

app = Flask(__name__)

# Whitelist of allowed operators and functions
ALLOWED_OPERATORS = {'+', '-', '*', '/', '**', '(', ')', '.', 'sqrt', 'sin', 'cos', 'tan'}

@app.route('/')
def index():
    return render_template('calculator.html')

@app.route('/calculate', methods=['POST'])
def calculate():
    expression = request.form.get('expression', '')

    # Input validation and sanitization
    if not expression or not isinstance(expression, str):
        return jsonify({'error': 'Invalid input'}), 400

    # Remove all whitespace
    expression = expression.replace(' ', '')

    # Validate that the expression only contains allowed characters/operators
    tokens = re.findall(r'\d+\.?\d*|[+\-*/().]|sqrt|sin|cos|tan', expression)
    for token in tokens:
        if not token.replace('.', '').isdigit() and token not in ALLOWED_OPERATORS:
            return jsonify({'error': 'Invalid operator or function'}), 400

    try:
        # Safe evaluation using a restricted environment
        # Convert expression to use Python's math functions
        expression = expression.replace('sqrt', 'math.sqrt')
        expression = expression.replace('sin', 'math.sin')
        expression = expression.replace('cos', 'math.cos')
        expression = expression.replace('tan', 'math.tan')

        # Create a restricted namespace for evaluation
        namespace = {'__builtins__': None, 'math': math}

        # Evaluate the expression in the restricted namespace
        result = eval(expression, namespace)

        return jsonify({'result': result})
    except Exception as e:
        return jsonify({'error': f'Calculation error: {str(e)}'}), 400

