from git import Repo
import logging
from pathlib import Path

# Set up logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

try:
    repo = Repo('/var/www/repo')
except Exception as e:
    logger.error(f"Failed to open repository: {e}")
    raise

def validate_paths(files):
    """Validate that files exist and are within the repository."""
    repo_path = Path('/var/www/repo')
    for file in files:
        file_path = Path(file)
        if not (repo_path / file_path).exists() and not file_path.is_absolute():
            # For adding new files, they might not exist yet
            continue
        # Prevent path traversal attacks by checking if resolved path is within repo
        if not (repo_path / file_path).resolve().is_relative_to(repo_path.resolve()):
            raise ValueError(f"Path traversal attempt detected: {file}")

def add(files):
    """Add files to the git index."""
    if not files:
        logger.warning("No files specified for adding")
        return

    validate_paths(files)
    try:
        repo.index.add(files)
        logger.info(f"Added files to index: {files}")
    except Exception as e:
        logger.error(f"Failed to add files: {e}")
        raise

def remove(files):
    """Remove files from the git index."""
    if not files:
        logger.warning("No files specified for removal")
        return

    validate_paths(files)
    try:
        repo.index.remove(files)
        logger.info(f"Removed files from index: {files}")
    except Exception as e:
        logger.error(f"Failed to remove files: {e}")
        raise

def commit(message):
    """Commit changes to the repository."""
    if not message or message.strip() == "":
        raise ValueError("Commit message cannot be empty")

    try:
        commit = repo.index.commit(message)
        logger.info(f"Created commit: {commit.hexsha}")
        return commit
    except Exception as e:
        logger.error(f"Failed to commit: {e}")
        raise

def push():
