    original_filename = db.Column(db.String(255), nullable=False)

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']

def validate_file_content(file_path):
    """Validate the file content matches its extension using python-magic"""
    mime = magic.Magic(mime=True)
    file_mime = mime.from_file(file_path)

    # Map of allowed MIME types
    allowed_mimes = {
        'image/jpeg': ['jpg', 'jpeg'],
        'image/png': ['png'],
        'image/gif': ['gif'],
        'video/mp4': ['mp4'],
        'application/pdf': ['pdf']
    }

    file_ext = os.path.splitext(file_path)[1][1:].lower()

    # Check if detected MIME type is allowed and matches the extension
    for mime_type, extensions in allowed_mimes.items():
        if file_mime == mime_type and file_ext in extensions:
            return True

    return False

