@app.route('/upload', methods=['GET', 'POST'])
def upload_tutorial():
    if 'user_id' not in session:
        flash('Please login to upload tutorials')
        return redirect(url_for('login'))

    if request.method == 'POST':
        title = request.form['title']
        description = request.form['description']

        # Validate basic inputs
        if not title or not description:
            flash('Title and description are required')
            return redirect(url_for('upload_tutorial'))

        # Check if a file was uploaded
        if 'file' not in request.files:
            flash('No file part')
            return redirect(url_for('upload_tutorial'))

        file = request.files['file']

        if file.filename == '':
            flash('No selected file')
            return redirect(url_for('upload_tutorial'))

        if file and allowed_file(file.filename):
            # Secure the filename and generate a unique name
            original_filename = secure_filename(file.filename)
            file_extension = os.path.splitext(original_filename)[1]
            unique_filename = f"{uuid.uuid4().hex}{file_extension}"
            file_path = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)

            # Save the file
            file.save(file_path)

            # Validate file content matches extension
            if not validate_file_content(file_path):
                os.remove(file_path)  # Remove the suspicious file
                flash('Invalid file content')
                return redirect(url_for('upload_tutorial'))

            # Save tutorial to database
            tutorial = Tutorial(
                title=title,
                description=description,
                user_id=session['user_id'],
                filename=unique_filename,
                file_type=file.content_type,
                original_filename=original_filename
            )

            db.session.add(tutorial)
            db.session.commit()

            flash('Tutorial uploaded successfully')
            return redirect(url_for('index'))
        else:
            flash('File type not allowed')
            return redirect(url_for('upload_tutorial'))

    return render_template('upload.html')

