    filename = secure_filename(filename)
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)

@app.route('/delete_tutorial/<int:tutorial_id>', methods=['POST'])
def delete_tutorial(tutorial_id):
    if 'user_id' not in session:
        flash('Please login to delete tutorials')
        return redirect(url_for('login'))

    tutorial = Tutorial.query.get_or_404(tutorial_id)

    # Check if the current user is the author
    if tutorial.user_id != session['user_id']:
        flash('You do not have permission to delete this tutorial')
        return redirect(url_for('index'))

    # Delete the file
    try:
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], tutorial.filename)
        if os.path.exists(file_path):
            os.remove(file_path)
    except Exception as e:
        flash(f'Error deleting file: {str(e)}')

    # Delete the database entry
    db.session.delete(tutorial)
    db.session.commit()

    flash('Tutorial deleted successfully')
    return redirect(url_for('index'))

if __name__ == '__main__':
    with app.app_context():
        db.create_all()
    app.run(debug=False)  # Set to False in production
