from urllib.parse import urlparse
import requests
from bs4 import BeautifulSoup
import time

def get_links(html):
    soup = BeautifulSoup(html, 'html.parser')
    anchors = soup.findAll('a')
    links = [a['href'] for a in anchors if 'href' in a.attrs]
    return [link for link in links if is_absolute(link)]

def is_absolute(url):
    parsed = urlparse(url)
    return bool(parsed.netloc) and bool(parsed.scheme)

def check_link(url):
    try:
        response = requests.head(url, timeout=10)
        if response.status_code in [301, 302, 303, 307, 308]:
            response = requests.head(response.headers['Location'], timeout=10)
        return response.status_code < 400
    except requests.RequestException:
        return False

def crawl(url, visited=None, depth=0, max_depth=3):
    if visited is None:
        visited = set()

    if url in visited or depth >= max_depth:
        return

    visited.add(url)

    try:
        response = requests.get(url, timeout=10)
        if response.status_code >= 400:
            print(f'Error accessing {url}: {response.status_code}')
            return

        html = response.text
        links = get_links(html)

        for link in links:
            if check_link(link):
                print(f'{link} is valid')
            else:
                print(f'{link} is broken')

            # Rate limiting to be respectful to servers
            time.sleep(1)

            # Recursively crawl with depth control
            crawl(link, visited, depth + 1, max_depth)

    except requests.RequestException as e:
        print(f'Failed to crawl {url}: {str(e)}')

