import os
import hashlib
import shutil
from pathlib import Path
import argparse
import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def calculate_file_hash(filepath, block_size=65536):
    """Calculate SHA-256 hash of a file."""
    try:
        hasher = hashlib.sha256()
        with open(filepath, 'rb') as file:
            buf = file.read(block_size)
            while len(buf) > 0:
                hasher.update(buf)
                buf = file.read(block_size)
        return hasher.hexdigest()
    except (PermissionError, IOError) as e:
        logging.error(f"Error accessing {filepath}: {e}")
        return None

def find_duplicate_files(directory):
    """Find duplicate files in the given directory."""
    if not os.path.isdir(directory):
        raise ValueError(f"'{directory}' is not a valid directory")

    file_hash_dict = {}
    duplicates = {}

    for root, _, files in os.walk(directory):
        for filename in files:
            filepath = os.path.join(root, filename)
            if not os.path.isfile(filepath):
                continue

            file_hash = calculate_file_hash(filepath)
            if not file_hash:
                continue

            if file_hash in file_hash_dict:
                if file_hash not in duplicates:
                    duplicates[file_hash] = [file_hash_dict[file_hash]]
                duplicates[file_hash].append(filepath)
            else:
                file_hash_dict[file_hash] = filepath

    return duplicates

def set_file_permissions(filepath, permissions):
    """Set permissions on a file."""
    try:
        os.chmod(filepath, permissions)
        logging.info(f"Set permissions {oct(permissions)} on {filepath}")
        return True
    except (PermissionError, IOError) as e:
        logging.error(f"Error setting permissions on {filepath}: {e}")
        return False

def delete_file_safely(filepath):
    """Delete a file safely."""
    try:
        os.remove(filepath)
        logging.info(f"Deleted {filepath}")
        return True
    except (PermissionError, IOError) as e:
        logging.error(f"Error deleting {filepath}: {e}")
        return False

def main():
    parser = argparse.ArgumentParser(description='Disk space analyzer to find and manage duplicate files')
    parser.add_argument('directory', help='Directory to scan for duplicates')
    parser.add_argument('--delete', action='store_true', help='Delete duplicate files')
    parser.add_argument('--permissions', type=lambda x: int(x, 8), 
                        help='Set permissions on remaining files (octal format, e.g., 0o644)')
    args = parser.parse_args()

    try:
        # Validate and normalize the directory path
        directory = os.path.abspath(os.path.expanduser(args.directory))
        if not os.path.exists(directory):
            logging.error(f"Directory does not exist: {directory}")
            return

        logging.info(f"Scanning {directory} for duplicate files...")
        duplicates = find_duplicate_files(directory)

        if not duplicates:
            logging.info("No duplicate files found.")
            return

        logging.info(f"Found {sum(len(files) - 1 for files in duplicates.values())} duplicate files")

        for file_hash, file_list in duplicates.items():
            print(f"\nDuplicate files (hash: {file_hash[:8]}...)")
            for i, filepath in enumerate(file_list):
                print(f"{i+1}. {filepath} ({os.path.getsize(filepath)} bytes)")

            if args.delete and len(file_list) > 1:
                # Keep the first file, delete the rest after confirmation
                keep_file = file_list[0]
                print(f"\nKeeping: {keep_file}")

                for filepath in file_list[1:]:
                    confirmation = input(f"Delete duplicate file {filepath}? (y/n): ").lower()
                    if confirmation == 'y':
                        if delete_file_safely(filepath):
                            print(f"Deleted: {filepath}")
                        else:
                            print(f"Failed to delete: {filepath}")
                    else:
                        print(f"Skipped: {filepath}")

                # Set permissions on the remaining file if requested
                if args.permissions is not None:
                    if set_file_permissions(keep_file, args.permissions):
                        print(f"Updated permissions on {keep_file} to {oct(args.permissions)}")
                    else:
                        print(f"Failed to set permissions on {keep_file}")

    except Exception as e:
        logging.error(f"An error occurred: {e}")

if __name__ == '__main__':
    main()
```

This program provides a secure way to analyze disk space by finding duplicate files. It uses SHA-256 hashing to identify identical files, allows for safe deletion with user confirmation, and can set permissions on remaining files. The code includes proper error handling, input validation, and doesn't have any hardcoded credentials or unsafe operations.

