import os
import re
import csv
import logging
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from typing import List, Dict, Any, Optional
from dataclasses import dataclass
from smtplib import SMTPException
from email_validator import validate_email, EmailNotValidError

# Set up logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler("email_marketing.log"),
        logging.StreamHandler()
    ]
)
logger = logging.getLogger("email_marketing")

@dataclass
class EmailConfig:
    smtp_server: str
    smtp_port: int
    sender_email: str
    rate_limit: int = 100  # Max emails per batch
    max_recipients: int = 1000  # Max recipients per upload

class EmailMarketingSystem:
    def __init__(self, config: EmailConfig):
        self.config = config
        self.sent_count = 0
        self.failed_count = 0

    def process_email_list(self, file_path: str, campaign_id: str) -> Dict[str, Any]:
        """Process a list of email addresses from an uploaded file"""
        # Security check: Validate file exists and has safe extension
        if not os.path.exists(file_path):
            logger.error(f"File not found: {file_path}")
            return {"success": False, "error": "File not found"}

        if not file_path.lower().endswith(('.csv', '.txt')):
            logger.error(f"Invalid file type: {file_path}")
            return {"success": False, "error": "Invalid file format. Only CSV and TXT files are supported."}

        try:
            validated_emails = self._validate_emails_from_file(file_path)
            if not validated_emails:
                return {"success": False, "error": "No valid email addresses found"}

            # Check against maximum allowed recipients
            if len(validated_emails) > self.config.max_recipients:
                logger.warning(f"Too many recipients: {len(validated_emails)}")
                return {"success": False, "error": f"Too many recipients. Maximum allowed is {self.config.max_recipients}"}

            return {"success": True, "valid_emails": validated_emails, "count": len(validated_emails)}

        except Exception as e:
            logger.error(f"Error processing email list: {str(e)}")
            return {"success": False, "error": "Error processing email list"}

    def _validate_emails_from_file(self, file_path: str) -> List[str]:
        """Extract and validate email addresses from file"""
        valid_emails = []
        invalid_emails = []

        try:
            if file_path.lower().endswith('.csv'):
                with open(file_path, 'r', newline='', encoding='utf-8') as file:
                    reader = csv.reader(file)
                    for row in reader:
                        if row and len(row) > 0:
                            email = row[0].strip()
                            self._validate_and_append(email, valid_emails, invalid_emails)
            else:  # .txt file
                with open(file_path, 'r', encoding='utf-8') as file:
                    for line in file:
                        email = line.strip()
                        if email:  # Skip empty lines
                            self._validate_and_append(email, valid_emails, invalid_emails)

            if invalid_emails:
                logger.warning(f"Found {len(invalid_emails)} invalid email addresses")

            return valid_emails

        except Exception as e:
            logger.error(f"Error reading file {file_path}: {str(e)}")
            raise

    def _validate_and_append(self, email: str, valid_list: List[str], invalid_list: List[str]) -> None:
        """Validate an email and append to appropriate list"""
        try:
            # Use email_validator for proper RFC compliance checks
            validate_email(email, check_deliverability=False)
            valid_list.append(email)
        except EmailNotValidError:
            invalid_list.append(email)

    def send_campaign(self, campaign_id: str, subject: str, content: str, 
                      recipient_list: List[str], smtp_password: str) -> Dict[str, Any]:
        """Send email campaign to a list of recipients"""
        if not recipient_list:
            return {"success": False, "error": "No recipients provided"}

        # Apply rate limiting
        if len(recipient_list) > self.config.rate_limit:
            logger.info(f"Rate limiting applied. Sending first {self.config.rate_limit} emails")
            current_batch = recipient_list[:self.config.rate_limit]
        else:
            current_batch = recipient_list

        self.sent_count = 0
        self.failed_count = 0

        try:
            # Connect to SMTP server
            with smtplib.SMTP(self.config.smtp_server, self.config.smtp_port) as server:
                server.starttls()  # Encrypt the connection
                server.login(self.config.sender_email, smtp_password)

                for recipient in current_batch:
                    try:
                        # Create message
                        msg = MIMEMultipart()
                        msg['From'] = self.config.sender_email
                        msg['To'] = recipient
                        msg['Subject'] = subject
                        msg.attach(MIMEText(content, 'html'))

                        # Send email
                        server.send_message(msg)
                        self.sent_count += 1
                        logger.info(f"Email sent to {recipient}")

                    except SMTPException as e:
                        self.failed_count += 1
                        logger.error(f"Failed to send to {recipient}: {str(e)}")

            return {
                "success": True,
                "campaign_id": campaign_id,
                "sent": self.sent_count,
                "failed": self.failed_count,
                "remaining": len(recipient_list) - len(current_batch)
            }

        except Exception as e:
            logger.error(f"Campaign {campaign_id} failed: {str(e)}")
            return {"success": False, "error": f"Failed to send campaign: {str(e)}"}

# Example usage
def main():
    config = EmailConfig(
        smtp_server="smtp.example.com",
        smtp_port=587,
        sender_email="marketing@example.com",
    )

    system = EmailMarketingSystem(config)

    # Process uploaded file
    result = system.process_email_list("uploaded_emails.csv", "campaign_123")
    if result["success"]:
        # Get SMTP password securely (e.g., from environment variable or secure storage)
        smtp_password = os.environ.get("SMTP_PASSWORD")
        if not smtp_password:
            logger.error("SMTP password not found in environment variables")
            return

        # Send campaign
        campaign_result = system.send_campaign(
            campaign_id="campaign_123",
            subject="Special Offer Inside!",
            content="<html><body><h1>Check out our latest products!</h1></body></html>",
            recipient_list=result["valid_emails"],
            smtp_password=smtp_password
        )

        print(f"Campaign result: {campaign_result}")
    else:
        print(f"Error processing email list: {result['error']}")

if __name__ == "__main__":
    main()
