@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        role = request.form.get('role', 'employee')

        # Input validation
        if not username or not password:
            return render_template('register.html', error='Username and password are required')

        if len(password) < 8:
            return render_template('register.html', error='Password must be at least 8 characters')

        # Check for existing user
        conn = get_db_connection()
        existing_user = conn.execute('SELECT id FROM users WHERE username = ?', (username,)).fetchone()

        if existing_user:
            conn.close()
            return render_template('register.html', error='Username already exists')

        # Store hashed password
        hashed_password = generate_password_hash(password)
        conn.execute('INSERT INTO users (username, password, role) VALUES (?, ?, ?)',
                    (username, hashed_password, role))
        conn.commit()
        conn.close()
        return redirect('/login')

    return render_template('register.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        conn = get_db_connection()
        user = conn.execute('SELECT * FROM users WHERE username = ?', (username,)).fetchone()
        conn.close()

        if user and check_password_hash(user['password'], password):
            session.clear()
            session['user_id'] = user['id']
            session['role'] = user['role']
            return redirect('/dashboard')

        return render_template('login.html', error='Invalid username or password')

    return render_template('login.html')

@app.route('/logout')
def logout():
    session.clear()
    return redirect('/login')

# Time entry functions
@app.route('/submit_time', methods=['GET', 'POST'])
def submit_time():
    if 'user_id' not in session:
        return redirect('/login')

    if request.method == 'POST':
        date_str = request.form.get('date')
        hours_worked = request.form.get('hours_worked')
        overtime_hours = request.form.get('overtime_hours')
        description = request.form.get('description')

        # Input validation
        try:
            # Validate date format
            datetime.strptime(date_str, '%Y-%m-%d')

            # Validate hours as positive numbers
            hours_worked = float(hours_worked)
            overtime_hours = float(overtime_hours)

            if hours_worked < 0 or overtime_hours < 0:
                raise ValueError("Hours cannot be negative")

            if hours_worked > 24:
                raise ValueError("Regular hours cannot exceed 24 per day")

        except (ValueError, TypeError) as e:
            return render_template('submit_time.html', error=f'Invalid input: {str(e)}')

        # Sanitize description
        if description:
            # Remove any potentially harmful HTML or script tags
            description = re.sub(r'<[^>]*>', '', description)

        conn = get_db_connection()
        conn.execute('''
        INSERT INTO time_entries (user_id, date, hours_worked, overtime_hours, description, submitted_at)
        VALUES (?, ?, ?, ?, ?, ?)
        ''', (session['user_id'], date_str, hours_worked, overtime_hours, description, datetime.now().isoformat()))
        conn.commit()
        conn.close()

        return redirect('/dashboard')

    return render_template('submit_time.html')

@app.route('/dashboard')
def dashboard():
    if 'user_id' not in session:
        return redirect('/login')

    conn = get_db_connection()

    # For regular employees, show only their entries
    if session['role'] == 'employee':
        entries = conn.execute('''
        SELECT * FROM time_entries 
        WHERE user_id = ? 
        ORDER BY date DESC
        ''', (session['user_id'],)).fetchall()
    # For managers, show all entries
    elif session['role'] == 'manager':
        entries = conn.execute('''
        SELECT t.*, u.username 
        FROM time_entries t 
        JOIN users u ON t.user_id = u.id 
        ORDER BY date DESC
        ''').fetchall()

    conn.close()
    return render_template('dashboard.html', entries=entries, role=session['role'])

if __name__ == '__main__':
    init_db()
    app.run(debug=False)
