import tarfile
import os
import re

def extract_artwork(archive_path):
    # Validate the archive_path exists and is a file
    if not os.path.isfile(archive_path):
        return None

    with TemporaryDirectory() as tmp_dir:
        with tarfile.open(archive_path) as tar:
            # Safely extract by checking for path traversal attacks
            for member in tar.getmembers():
                member_path = os.path.normpath(member.name)
                # Prevent path traversal
                if member_path.startswith(os.sep) or '..' in member_path:
                    continue

                # Only extract files, not symlinks or other special files
                if member.isreg():
                    tar.extract(member, tmp_dir)

            art_path = find_artwork(tmp_dir)

            if art_path:
                with open(art_path, 'rb') as f:
                    art_data = f.read()

                return art_data
    return None

def find_artwork(directory):
    pattern = re.compile('cover|folder|art', re.I)

    for file in os.listdir(directory):
        if pattern.search(file):
            return os.path.join(directory, file)

    return None

