import os
import re
import argparse
from collections import Counter, defaultdict
from datetime import datetime
import logging

logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

class LogAnalyzer:
    def __init__(self, log_path=None):
        self.log_path = log_path
        self.log_data = []
        self.stats = {
            'total_entries': 0,
            'errors': 0,
            'warnings': 0,
            'info': 0,
            'by_date': defaultdict(int),
            'by_ip': defaultdict(int),
            'by_endpoint': defaultdict(int),
            'status_codes': Counter(),
        }

    def validate_file_path(self, file_path):
        """Validate that the file exists and is a regular file."""
        if not os.path.exists(file_path):
            raise FileNotFoundError(f"Log file not found: {file_path}")
        if not os.path.isfile(file_path):
            raise ValueError(f"Path is not a file: {file_path}")
        # Check file is readable
        if not os.access(file_path, os.R_OK):
            raise PermissionError(f"No permission to read file: {file_path}")
        return True

    def parse_log_file(self, log_path=None):
        """Parse the log file and extract relevant information."""
        file_path = log_path or self.log_path
        if not file_path:
            raise ValueError("No log file path provided")

        try:
            self.validate_file_path(file_path)

            # Common log patterns - adjust for your specific log format
            apache_pattern = r'(\S+) (\S+) (\S+) \[([\w:/]+\s[+\-]\d{4})\] "(\S+) (\S+) (\S+)" (\d{3}) (\d+)'
            error_pattern = r'\[(\w+)\]'

            with open(file_path, 'r', encoding='utf-8') as file:
                for line_num, line in enumerate(file, 1):
                    try:
                        line = line.strip()
                        if not line:
                            continue

                        # For this example, we'll try to parse both Apache-style and simple error logs
                        apache_match = re.match(apache_pattern, line)
                        error_match = re.search(error_pattern, line)

                        log_entry = {'raw': line, 'line_num': line_num}

                        if apache_match:
                            ip, _, _, timestamp, method, endpoint, protocol, status, size = apache_match.groups()
                            log_entry.update({
                                'ip': ip,
                                'timestamp': timestamp,
                                'method': method,
                                'endpoint': endpoint,
                                'protocol': protocol,
                                'status': int(status),
                                'size': int(size)
                            })

                            # Update stats
                            self.stats['by_ip'][ip] += 1
                            self.stats['by_endpoint'][endpoint] += 1
                            self.stats['status_codes'][status] += 1

                            # Extract date for date-based stats
                            try:
                                date_str = timestamp.split(':')[0]
                                self.stats['by_date'][date_str] += 1
                            except Exception as e:
                                logging.warning(f"Could not parse date from timestamp {timestamp}: {e}")

                        elif error_match:
                            level = error_match.group(1).lower()
                            log_entry['level'] = level

                            if level == 'error':
                                self.stats['errors'] += 1
                            elif level == 'warning':
                                self.stats['warnings'] += 1
                            elif level == 'info':
                                self.stats['info'] += 1

                        self.log_data.append(log_entry)
                        self.stats['total_entries'] += 1

                    except Exception as e:
                        logging.error(f"Error parsing line {line_num}: {e}")

        except Exception as e:
            logging.error(f"Error processing log file: {e}")
            raise

        return self.stats

    def generate_report(self, output_file=None):
        """Generate a report from the analyzed log data."""
        if not self.log_data:
            logging.warning("No log data to generate report from. Run parse_log_file first.")
            return None

        report = [
            "=== Log Analysis Report ===",
            f"Total entries processed: {self.stats['total_entries']}",
            f"Errors: {self.stats['errors']}",
            f"Warnings: {self.stats['warnings']}",
            f"Info: {self.stats['info']}",

            "\n=== Top 10 IPs ==="
        ]

        for ip, count in sorted(self.stats['by_ip'].items(), key=lambda x: x[1], reverse=True)[:10]:
            report.append(f"{ip}: {count}")

        report.append("\n=== Top 10 Endpoints ===")
        for endpoint, count in sorted(self.stats['by_endpoint'].items(), key=lambda x: x[1], reverse=True)[:10]:
            report.append(f"{endpoint}: {count}")

        report.append("\n=== Status Code Distribution ===")
        for status, count in sorted(self.stats['status_codes'].items()):
            report.append(f"Status {status}: {count}")

        report_text = "\n".join(report)

        if output_file:
            try:
                # Make sure we're not writing outside intended directory
                output_path = os.path.abspath(output_file)
                with open(output_path, 'w', encoding='utf-8') as f:
                    f.write(report_text)
                logging.info(f"Report saved to {output_path}")
            except Exception as e:
                logging.error(f"Error writing report to file: {e}")

        return report_text

    def get_errors(self):
        """Extract and return all error entries."""
        return [entry for entry in self.log_data if entry.get('level') == 'error']

    def get_entries_by_status(self, status_code):
        """Get all entries with a specific status code."""
        if not isinstance(status_code, int):
            try:
                status_code = int(status_code)
            except ValueError:
                raise ValueError("Status code must be an integer")

        return [entry for entry in self.log_data if entry.get('status') == status_code]

def main():
    parser = argparse.ArgumentParser(description='Analyze log files and generate reports')
    parser.add_argument('log_file', help='Path to the log file to analyze')
    parser.add_argument('--output', '-o', help='Output file for the report')
    args = parser.parse_args()

    try:
        analyzer = LogAnalyzer()
        analyzer.parse_log_file(args.log_file)
        report = analyzer.generate_report(args.output)

        if not args.output:
            print(report)

    except Exception as e:
        logging.error(f"Analysis failed: {e}")
        return 1

    return 0

if __name__ == "__main__":
    exit(main())

