app.config["MAX_CONTENT_LENGTH"] = 16 * 1024 * 1024  # 16MB max upload

ALLOWED_EXTENSIONS = {"mp3", "wav", "ogg", "flac"}

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route("/convert", methods=["POST"])
def convert_audio():
    if "audio_file" not in request.files:
        return abort(400, description="No audio file provided")

    audio_file = request.files["audio_file"]
    if audio_file.filename == "":
        return abort(400, description="No filename provided")

    if not allowed_file(audio_file.filename):
        return abort(400, description="File type not allowed")

    output_format = request.form.get("format", "mp3").lower()
    if output_format not in ALLOWED_EXTENSIONS:
        return abort(400, description="Output format not allowed")

    # Create a safe filename with UUID to prevent conflicts
    original_filename = os.path.basename(audio_file.filename)
    safe_filename = f"{uuid.uuid4()}_{original_filename}"

    # Ensure the audio directory exists
    os.makedirs(app.config["AUDIO_DIR"], exist_ok=True)

    # Create full path for audio file
    audio_path = os.path.join(app.config["AUDIO_DIR"], safe_filename)

    # Save the uploaded file
    audio_file.save(audio_path)

    # Verify file is actually audio using magic
    mime = magic.Magic(mime=True)
    file_type = mime.from_file(audio_path)
    if not file_type.startswith('audio/'):
        os.remove(audio_path)  # Clean up non-audio file
        return abort(400, description="File is not a valid audio file")

    try:
        # Convert the audio
        output_filename = f"{os.path.splitext(safe_filename)[0]}.{output_format}"
        output_path = os.path.join(app.config["AUDIO_DIR"], output_filename)

        audio = AudioSegment.from_file(audio_path)
        audio.export(output_path, format=output_format)

        # Clean up the original file
        os.remove(audio_path)

        return {"success": True, "filename": output_filename}
    except Exception as e:
        # Clean up in case of errors
        if os.path.exists(audio_path):
            os.remove(audio_path)
        return abort(500, description=f"Error converting audio: {str(e)}")

@app.route("/audio/<filename>")
def get_audio(filename):
    # Prevent path traversal
    filename = os.path.basename(filename)
    return send_from_directory(app.config["AUDIO_DIR"], filename)

