import os
import requests
import re
from urllib.parse import urlparse

class MapDownloader:
    def __init__(self, map_dir, max_size_mb=100):
        self.map_dir = map_dir
        self.max_size_mb = max_size_mb
        self.ensure_dir_exists()

    def ensure_dir_exists(self):
        if not os.path.exists(self.map_dir):
            os.makedirs(self.map_dir)

    def is_valid_url(self, url):
        parsed = urlparse(url)
        return bool(parsed.netloc) and bool(parsed.scheme)

    def download_map(self, url):
        # Validate URL format
        if not self.is_valid_url(url):
            raise ValueError("Invalid URL format")

        # Get filename and sanitize it
        filename = os.path.basename(urlparse(url).path)
        if not filename or '..' in filename:
            raise ValueError("Invalid filename in URL")

        # Ensure the filename only contains safe characters
        if not re.match(r'^[a-zA-Z0-9_.-]+$', filename):
            raise ValueError("Filename contains invalid characters")

        dest_path = os.path.join(self.map_dir, filename)

        try:
            # Download with timeout and stream to check size before saving
            with requests.get(url, stream=True, timeout=30) as resp:
                resp.raise_for_status()  # Raise exception for HTTP errors

                # Check content size
                content_length = int(resp.headers.get('Content-Length', 0))
                if content_length > self.max_size_mb * 1024 * 1024:
                    raise ValueError(f"File too large: {content_length} bytes exceeds limit of {self.max_size_mb}MB")

                # Save file safely
                with open(dest_path, 'wb') as f:
                    for chunk in resp.iter_content(chunk_size=8192):
                        f.write(chunk)

            return dest_path
        except requests.RequestException as e:
            raise RuntimeError(f"Error downloading map: {str(e)}")

downloader = MapDownloader('data/maps')
