        destination = request.form.get('destination', '')
        checkin = request.form.get('checkin', '')
        checkout = request.form.get('checkout', '')

        # Validate inputs
        if not destination or not checkin or not checkout:
            return jsonify({'error': 'Missing required fields'}), 400

        # Validate date format (YYYY-MM-DD)
        date_pattern = re.compile(r'^\d{4}-\d{2}-\d{2}$')
        if not (date_pattern.match(checkin) and date_pattern.match(checkout)):
            return jsonify({'error': 'Invalid date format. Use YYYY-MM-DD'}), 400

        # Validate dates are in the future and checkout is after checkin
        try:
            checkin_date = datetime.strptime(checkin, '%Y-%m-%d')
            checkout_date = datetime.strptime(checkout, '%Y-%m-%d')
            today = datetime.now()

            if checkin_date < today or checkout_date < today:
                return jsonify({'error': 'Dates must be in the future'}), 400

            if checkout_date < checkin_date:
                return jsonify({'error': 'Checkout date must be after checkin date'}), 400
        except ValueError:
            return jsonify({'error': 'Invalid date values'}), 400

        flight = {
            'destination': destination,
            'checkin': checkin,
            'checkout': checkout,
            'booking_time': datetime.now().isoformat(),
            'status': 'confirmed'
        }

        # Generate a unique booking reference
        booking_ref = str(uuid.uuid4())
        booked_flights[booking_ref] = flight

        # Log the booking (would go to proper logging system in production)
        logging.info(f"Flight booked: {booking_ref} to {destination}")

        # Return success response with booking reference
        return jsonify({
            'success': True,
            'message': 'Flight booked successfully',
            'booking_reference': booking_ref,
            'flight_details': flight
        }), 201

    except Exception as e:
        # Log the error but don't expose details to the client
        logging.error(f"Error processing booking: {str(e)}")
        return jsonify({'error': 'An error occurred processing your booking'}), 500

@app.route('/booking/<booking_ref>', methods=['GET'])
def get_booking(booking_ref):
    # Validate booking reference format
    if not booking_ref or not re.match(r'^[0-9a-f-]{36}$', booking_ref):
        return jsonify({'error': 'Invalid booking reference format'}), 400

    # Look up the booking
    flight = booked_flights.get(booking_ref)
    if not flight:
        return jsonify({'error': 'Booking not found'}), 404

    return jsonify({
        'booking_reference': booking_ref,
        'flight_details': flight
    })

