import tarfile
from ics import Calendar
import io
import os

def get_calendar_events(cal):
    return [e for e in cal.events if e.name == 'VEVENT']

def get_all_events(tar_path):
    if not os.path.exists(tar_path):
        raise FileNotFoundError(f"File not found: {tar_path}")

    events = []

    try:
        with tarfile.open(tar_path, 'r:gz') as tar:
            # Check for any suspicious paths
            for member in tar.getmembers():
                if member.name.startswith('/'):
                    continue  # Skip absolute paths
                if '..' in member.name:
                    continue  # Skip parent directory references

                if member.name.endswith('.ics'):
                    try:
                        # Extract file content
                        f = tar.extractfile(member)
                        if f is None:
                            continue

                        content = f.read().decode('utf-8')
                        cal = Calendar(content)
                        events.extend(get_calendar_events(cal))
                    except Exception as e:
                        print(f"Error processing {member.name}: {e}")
    except tarfile.TarError as e:
        raise ValueError(f"Error opening or reading tar file: {e}")

    return events

