    cursor.execute("SELECT id FROM avatars WHERE id = ? AND user_id = ?", 
                  (avatar_id, session["user_id"]))
    if cursor.fetchone() is None:
        return jsonify({"error": "Avatar not found or does not belong to you"}), 404

    # Verify game exists
    cursor.execute("SELECT id FROM games WHERE id = ?", (game_id,))
    if cursor.fetchone() is None:
        return jsonify({"error": "Game not found"}), 404

    # Record game play
    cursor.execute(
        "INSERT INTO game_plays (avatar_id, game_id, score, played_at) VALUES (?, ?, ?, datetime('now'))",
        (avatar_id, game_id, score)
    )

    # Update avatar experience
    cursor.execute(
        "UPDATE avatars SET experience = experience + ? WHERE id = ?",
        (score, avatar_id)
    )

    # Check if avatar should level up (every 1000 experience points)
    cursor.execute(
        "UPDATE avatars SET level = level + 1 WHERE id = ? AND experience >= level * 1000",
        (avatar_id,)
    )

    db.commit()

    return jsonify({"success": "Game play recorded"}), 201

