import os
import tarfile
import subprocess
import tempfile
import shutil
import re

def convert_video(video_path, output_format):
    # Validate input parameters
    if not os.path.isfile(video_path):
        raise ValueError(f"Input file does not exist: {video_path}")
    if not re.match(r'^[a-zA-Z0-9]+$', output_format):
        raise ValueError(f"Invalid output format: {output_format}")

    # Create output filename
    base_name = os.path.splitext(video_path)[0]
    output_path = f"{base_name}.{output_format}"

    # Use ffmpeg for conversion
    try:
        subprocess.run(
            ["ffmpeg", "-i", video_path, "-c:v", "libx264", "-c:a", "aac", output_path],
            check=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE
        )
        print(f"Successfully converted {video_path} to {output_path}")
        return output_path
    except subprocess.CalledProcessError as e:
        print(f"Error converting {video_path}: {e}")
        return None

def convert_videos_in_dir(dir_path, output_format):
    for fname in os.listdir(dir_path):
        video_path = os.path.join(dir_path, fname)
        if os.path.isfile(video_path) and fname.endswith((".mp4", ".mov", ".avi")):
            convert_video(video_path, output_format)

def convert_videos_in_tarball(tar_path, output_format):
    # Validate input parameters
    if not os.path.isfile(tar_path):
        raise ValueError(f"Tarball does not exist: {tar_path}")
    if not re.match(r'^[a-zA-Z0-9]+$', output_format):
        raise ValueError(f"Invalid output format: {output_format}")

    # Create a secure temporary directory
    temp_dir = tempfile.mkdtemp(prefix="video_conversion_")

    try:
        # Open and validate the tar file
        try:
            tar = tarfile.open(tar_path)
        except tarfile.ReadError:
            raise ValueError(f"Invalid or corrupted tarball: {tar_path}")

        # Check for dangerous paths before extraction
        for member in tar.getmembers():
            if member.name.startswith('/') or '..' in member.name:
                raise ValueError(f"Potentially unsafe path in tarball: {member.name}")

        # Extract to temp directory
        tar.extractall(path=temp_dir)
        tar.close()

        # Process videos in the extracted directory
        for root, dirs, files in os.walk(temp_dir):
            for file in files:
                if file.endswith((".mp4", ".mov", ".avi")):
                    video_path = os.path.join(root, file)
                    convert_video(video_path, output_format)

    finally:
        # Clean up temporary files
        if os.path.exists(temp_dir):
            shutil.rmtree(temp_dir)

