import os
import shutil
import pathlib

def make_backup(input_dir):
    # Validate input directory exists
    if not os.path.isdir(input_dir):
        raise ValueError(f"Input directory '{input_dir}' does not exist")

    # Create backup with a secure filename
    backup_path = 'backup.tar.gz'
    try:
        with tarfile.open(backup_path, 'w:gz') as tar:
            for root, _, files in os.walk(input_dir):
                for file in files:
                    file_path = os.path.join(root, file)
                    # Only add regular files, not symlinks
                    if os.path.isfile(file_path) and not os.path.islink(file_path):
                        tar.add(file_path, arcname=os.path.relpath(file_path, input_dir))
        return backup_path
    except Exception as e:
        # Clean up partial backup if an error occurs
        if os.path.exists(backup_path):
            os.remove(backup_path)
        raise RuntimeError(f"Backup failed: {str(e)}")

def restore_backup(output_dir):
    # Validate output directory exists
    if not os.path.isdir(output_dir):
        raise ValueError(f"Output directory '{output_dir}' does not exist")

    backup_path = 'backup.tar.gz'
    if not os.path.exists(backup_path):
        raise FileNotFoundError(f"Backup file '{backup_path}' not found")

    # Create a temporary directory for extraction
    temp_dir = os.path.join(output_dir, 'temp_extract')
    try:
        os.makedirs(temp_dir, exist_ok=True)

        # Open and extract the tar file safely
        with tarfile.open(backup_path, 'r:gz') as tar:
            # Check for path traversal attempts before extracting
            for member in tar.getmembers():
                member_path = os.path.normpath(member.name)
                if member_path.startswith(('/', '..' + os.sep)):
                    raise ValueError(f"Potentially unsafe path in archive: {member.name}")

            # Extract files to the temporary directory
            tar.extractall(path=temp_dir)

        # Move extracted files to the output directory
        for item in os.listdir(temp_dir):
            src = os.path.join(temp_dir, item)
            dest = os.path.join(output_dir, item)
            # Handle existing files safely
            if os.path.exists(dest):
                if os.path.isdir(dest):
                    shutil.rmtree(dest)
                else:
                    os.remove(dest)
            shutil.move(src, output_dir)
    finally:
        # Clean up the temporary directory
        if os.path.exists(temp_dir):
            shutil.rmtree(temp_dir)

